on_id   BIGINT NOT NULL REFERENCES stations(id),\\r\\n26:     destination_station_id BIGINT NOT NULL REFERENCES stations(id),\\r\\n27:     departure_at        TIMESTAMPTZ NOT NULL,\\r\\n28:     arrival_at          TIMESTAMPTZ NOT NULL,\\r\\n29:     status              VARCHAR(20) NOT NULL DEFAULT 'scheduled',\\r\\n30:     created_at          TIMESTAMPTZ NOT NULL DEFAULT CURRENT_TIMESTAMP,\\r\\n31:     updated_at          TIMESTAMPTZ NOT NULL DEFAULT CURRENT_TIMESTAMP,\\r\\n32:     UNIQUE (train_id, service_date),\\r\\n33:     CHECK (origin_station_id \u003c\u003e destination_station_id),\\r\\n34:     CHECK (arrival_at \u003e departure_at),\\r\\n35:     CHECK (status IN ('scheduled', 'boarding', 'departed', 'completed', 'cancelled'))\\r\\n36: );\\r\\n37: \\r\\n38: CREATE TABLE segments (\\r\\n39:     id                  BIGINT GENERATED ALWAYS AS IDENTITY PRIMARY KEY,\\r\\n40:     trip_id             BIGINT NOT NULL REFERENCES trips(id) ON DELETE CASCADE,\\r\\n41:     sequence_no         INTEGER NOT NULL,\\r\\n42:     origin_station_id   BIGINT NOT NULL REFERENCES stations(id),\\r\\n43:     destination_station_id BIGINT NOT NULL REFERENCES stations(id),\\r\\n44:     departure_at        TIMESTAMPTZ NOT NULL,\\r\\n45:     arrival_at          TIMESTAMPTZ NOT NULL,\\r\\n46:     distance_km         NUMERIC(8,2) NOT NULL,\\r\\n47:     created_at          TIMESTAMPTZ NOT NULL DEFAULT CURRENT_TIMESTAMP,\\r\\n48:     UNIQUE (trip_id, sequence_no),\\r\\n49:     UNIQUE (trip_id, origin_station_id, destination_station_id),\\r\\n50:     CHECK (sequence_no \u003e 0),\\r\\n51:     CHECK (origin_station_id \u003c\u003e destination_station_id),\\r\\n52:     CHECK (arrival_at \u003e departure_at),\\r\\n53:     CHECK (distance_km \u003e 0)\\r\\n54: );\\r\\n55: \\r\\n56: CREATE TABLE seats (\\r\\n57:     id              BIGINT GENERATED ALWAYS AS IDENTITY PRIMARY KEY,\\r\\n58:     trip_id         BIGINT NOT NULL REFERENCES trips(id) ON DELETE CASCADE,\\r\\n59:     coach_no        VARCHAR(10) NOT NULL,\\r\\n60:     seat_no         VARCHAR(10) NOT NULL,\\r\\n61:     seat_type       VARCHAR(30) NOT NULL,\\r\\n62:     status          VARCHAR(20) NOT NULL DEFAULT 'available',\\r\\n63:     created_at      TIMESTAMPTZ NOT NULL DEFAULT CURRENT_TIMESTAMP,\\r\\n64:     UNIQUE (trip_id, coach_no, seat_no),\\r\\n65:     CHECK (status IN ('available', 'locked', 'maintenance'))\\r\\n66: );\\r\\n67: \\r\\n68: CREATE TABLE od_products (\\r\\n69:     id                  BIGINT GENERATED ALWAYS AS IDENTITY PRIMARY KEY,\\r\\n70:     trip_id             BIGINT NOT NULL REFERENCES trips(id) ON DELETE CASCADE,\\r\\n71:     origin_station_id   BIGINT NOT NULL REFERENCES stations(id),\\r\\n72:     destination_station_id BIGINT NOT NULL REFERENCES stations(id),\\r\\n73:     seat_type           VARCHAR(30) NOT NULL,\\r\\n74:     fare_class          VARCHAR(30) NOT NULL DEFAULT 'standard',\\r\\n75:     base_price          NUMERIC(14,2) NOT NULL,\\r\\n76:     distance_km         NUMERIC(8,2) NOT NULL,\\r\\n77:     is_active           BOOLEAN NOT NULL DEFAULT TRUE,\\r\\n78:     created_at          TIMESTAMPTZ NOT NULL DEFAULT CURRENT_TIMESTAMP,\\r\\n79:     updated_at          TIMESTAMPTZ NOT NULL DEFAULT CURRENT_TIMESTAMP,\\r\\n80:     UNIQUE (trip_id, origin_station_id, destination_station_id, seat_type, fare_class),\\r\\n81:     CHECK (origin_station_id \u003c\u003e destination_station_id),\\r\\n82:     CHECK (base_price \u003e= 0),\\r\\n83:     CHECK (distance_km \u003e 0)\\r\\n84: );\\r\\n85: \\r\\n86: CREATE TABLE bookings (\\r\\n87:     id              BIGINT GENERATED ALWAYS AS IDENTITY PRIMARY KEY,\\r\\n88:     booking_code    VARCHAR(50) NOT NULL UNIQUE,\\r\\n89:     od_product_id   BIGINT NOT NULL REFERENCES od_products(id),\\r\\n90:     seat_id         BIGINT REFERENCES seats(id),\\r\\n91:     status          VARCHAR(20) NOT NULL DEFAULT 'confirmed',\\r\\n92:     channel         VARCHAR(30),\\r\\n93:     booked_price    NUMERIC(14,2) NOT NULL,\\r\\n94:     booked_at       TIMESTAMPTZ NOT NULL,\\r\\n95:     cancelled_at    TIMESTAMPTZ,\\r\\n96:     refunded_at     TIMESTAMPTZ,\\r\\n97:     created_at      TIMESTAMPTZ NOT NULL DEFAULT CURRENT_TIMESTAMP,\\r\\n98:     updated_at      TIMESTAMPTZ NOT NULL DEFAULT CURRENT_TIMESTAMP,\\r\\n99:     CHECK (status IN ('held', 'confirmed', 'cancelled', 'refunded')),\\r\\n100:     CHECK (booked_price \u003e= 0),\\r\\n101:     CHECK (cancelled_at IS NULL OR cancelled_at \u003e= booked_at),\\r\\n102:     CHECK (refunded_at IS NULL OR refunded_at \u003e= booked_at)\\r\\n103: );\\r\\n104: \\r\\n105: CREATE TABLE demand_forecasts (\\r\\n106:     id                  BIGINT GENERATED ALWAYS AS IDENTITY PRIMARY KEY,\\r\\n107:     od_product_id       BIGINT NOT NULL REFERENCES od_products(id) ON DELETE CASCADE,\\r\\n108:     forecast_at         TIMESTAMPTZ NOT NULL,\\r\\n109:     lead_days           INTEGER NOT NULL,\\r\\n110:     demand_point        NUMERIC(12,3) NOT NULL,\\r\\n111:     demand_p10          NUMERIC(12,3),\\r\\n112:     demand_p50          NUMERIC(12,3),\\r\\n113:     demand_p90          NUMERIC(12,3),\\r\\n114:     model_version       VARCHAR(80),\\r\\n115:     created_at          TIMESTAMPTZ NOT NULL DEFAULT CURRENT_TIMESTAMP,\\r\\n116:     UNIQUE (od_product_id, forecast_at, lead_days),\\r\\n117:     CHECK (lead_days \u003e= 0),\\r\\n118:     CHECK (demand_point \u003e= 0),\\r\\n119:     CHECK (demand_p10 IS NULL OR demand_p10 \u003e= 0),\\r\\n120:     CHECK (demand_p50 IS NULL OR demand_p50 \u003e= 0),\\r\\n121:     CHECK (demand_p90 IS NULL OR demand_p90 \u003e= 0),\\r\\n122:     CHECK (demand_p10 IS NULL OR demand_p50 IS NULL OR demand_p10 \u003c= demand_p50),\\r\\n123:     CHECK (demand_p50 IS NULL OR demand_p90 IS NULL OR demand_p50 \u003c= demand_p90)\\r\\n124: );\\r\\n125: \\r\\n126: CREATE TABLE bid_prices (\\r\\n127:     id              BIGINT GENERATED ALWAYS AS IDENTITY PRIMARY KEY,\\r\\n128:     segment_id      BIGINT NOT NULL REFERENCES segments(id) ON DELETE CASCADE,\\r\\n129:     seat_type       VARCHAR(30) NOT NULL,\\r\\n130:     bid_price       NUMERIC(14,2) NOT NULL,\\r\\n131:     remaining_capacity INTEGER NOT NULL,\\r\\n132:     calculated_at   TIMESTAMPTZ NOT NULL,\\r\\n133:     run_version     VARCHAR(80) NOT NULL,\\r\\n134:     is_active       BOOLEAN NOT NULL DEFAULT TRUE,\\r\\n135:     created_at      TIMESTAMPTZ NOT NULL DEFAULT CURRENT_TIMESTAMP,\\r\\n136:     UNIQUE (segment_id, seat_type, run_version),\\r\\n137:     CHECK (bid_price \u003e= 0),\\r\\n138:     CHECK (remaining_capacity \u003e= 0)\\r\\n139: );\\r\\n140: \\r\\n141: CREATE TABLE quotas (\\r\\n142:     id              BIGINT GENERATED ALWAYS AS IDENTITY PRIMARY KEY,\\r\\n143:     od_product_id   BIGINT NOT NULL REFERENCES od_products(id) ON DELETE CASCADE,\\r\\n144:     quota           INTEGER NOT NULL,\\r\\n145:     calculated_at   TIMESTAMPTZ NOT NULL,\\r\\n146:     run_version     VARCHAR(80) NOT NULL,\\r\\n147:     is_active       BOOLEAN NOT NULL DEFAULT TRUE,\\r\\n148:     created_at      TIMESTAMPTZ NOT NULL DEFAULT CURRENT_TIMESTAMP,\\r\\n149:     UNIQUE (od_product_id, run_version),\\r\\n150:     CHECK (quota \u003e= 0)\\r\\n151: );\\r\\n152: \\r\\n153: CREATE TABLE price_policies (\\r\\n154:     id                  BIGINT GENERATED ALWAYS AS IDENTITY PRIMARY KEY,\\r\\n155:     od_product_id       BIGINT REFERENCES od_products(id) ON DELETE CASCADE,\\r\\n156:     name                VARCHAR(120) NOT NULL,\\r\\n157:     min_price           NUMERIC(14,2) NOT NULL,\\r\\n158:     max_price           NUMERIC(14,2) NOT NULL,\\r\\n159:     max_step_change     NUMERIC(14,2) NOT NULL,\\r\\n160:     valid_from          TIMESTAMPTZ NOT NULL,\\r\\n161:     valid_to            TIMESTAMPTZ,\\r\\n162:     status              VARCHAR(20) NOT NULL DEFAULT 'draft',\\r\\n163:     created_by          VARCHAR(120),\\r\\n164:     approved_by         VARCHAR(120),\\r\\n165:     created_at          TIMESTAMPTZ NOT NULL DEFAULT CURRENT_TIMESTAMP,\\r\\n166:     updated_at          TIMESTAMPTZ NOT NULL DEFAULT CURRENT_TIMESTAMP,\\r\\n167:     CHECK (min_price \u003e= 0),\\r\\n168:     CHECK (max_price \u003e= min_price),\\r\\n169:     CHECK (max_step_change \u003e= 0),\\r\\n170:     CHECK (valid_to IS NULL OR valid_to \u003e valid_from),\\r\\n171:     CHECK (status IN ('draft', 'active', 'inactive'))\\r\\n172: );\\r\\n173: \\r\\n174: CREATE TABLE price_quotes (\\r\\n175:     id                  BIGINT GENERATED ALWAYS AS IDENTITY PRIMARY KEY,\\r\\n176:     od_product_id       BIGINT NOT NULL REFERENCES od_products(id),\\r\\n177:     policy_id           BIGINT REFERENCES price_policies(id),\\r\\n178:     opportunity_cost    NUMERIC(14,2) NOT NULL,\\r\\n179:     proposed_price      NUMERIC(14,2) NOT NULL,\\r\\n180:     final_price         NUMERIC(14,2) NOT NULL,\\r\\n181:     decision            VARCHAR(20) NOT NULL,\\r\\n182:     explanation         JSONB NOT NULL DEFAULT '{}'::JSONB,\\r\\n183:     run_version         VARCHAR(80),\\r\\n184:     quoted_at           TIMESTAMPTZ NOT NULL DEFAULT CURRENT_TIMESTAMP,\\r\\n185:     expires_at          TIMESTAMPTZ,\\r\\n186:     confirmed_at        TIMESTAMPTZ,\\r\\n187:     created_at          TIMESTAMPTZ NOT NULL DEFAULT CURRENT_TIMESTAMP,\\r\\n188:     CHECK (opportunity_cost \u003e= 0),\\r\\n189:     CHECK (proposed_price \u003e= 0),\\r\\n190:     CHECK (final_price \u003e= 0),\\r\\n191:     CHECK (decision IN ('accepted', 'rejected', 'blocked')),\\r\\n192:     CHECK (expires_at IS NULL OR expires_at \u003e quoted_at),\\r\\n193:     CHECK (confirmed_at IS NULL OR confirmed_at \u003e= quoted_at)\\r\\n194: );\\r\\n195: \\r\\n196: CREATE TABLE audit_logs (\\r\\n197:     id              BIGINT GENERATED ALWAYS AS IDENTITY PRIMARY KEY,\\r\\n198:     actor           VARCHAR(120) NOT NULL,\\r\\n199:     action          VARCHAR(60) NOT NULL,\\r\\n200:     entity_type     VARCHAR(60) NOT NULL,\\r\\n201:     entity_id       VARCHAR(80),\\r\\n202:     before_data     JSONB,\\r\\n203:     after_data      JSONB,\\r\\n204:     created_at      TIMESTAMPTZ NOT NULL DEFAULT CURRENT_TIMESTAMP\\r\\n205: );\\r\\n206: \\nThe above content shows the entire, complete file contents of the requested file.\\n\"}"}
{"File":"c:\\Users\\vando\\OneDrive\\Desktop\\Hackathon-Viber-Code-Pro-Max\\docs\\ai-log\\sessions\\2026-07-17-gemini-838552a4.jsonl","LineNumber":112,"LineContent":"{\"step_index\":112,\"source\":\"MODEL\",\"type\":\"VIEW_FILE\",\"status\":\"DONE\",\"created_at\":\"2026-07-17T11:47:31Z\",\"content\":\"Created At: 2026-07-17T11:47:31Z\\nCompleted At: 2026-07-17T11:47:32Z\\nFile Path: `file:///c:/Users/vando/OneDrive/Desktop/Hackathon-Viber-Code-Pro-Max/DATABASE_SCHEMA.md`\\nTotal Lines: 419\\nTotal Bytes: 25768\\nShowing lines 1 to 419\\nThe following code has been modified to include a line number before every line, in the format: \u003cline_number\u003e: \u003coriginal_line\u003e. Please note that any changes targeting the original code should remove the line number, colon, and leading space.\\n1: # Database Schema — SRRM MVP\\r\\n2: \\r\\n3: Tài liệu này mô tả schema PostgreSQL trong [`schema.sql`](schema.sql) của hệ thống **Smart Rail Revenue Management (SRRM)**. Schema gồm **21 bảng**, **5 index tường minh**, **1 trigger function** và **7 trigger**, phục vụ dữ liệu vận hành, tồn kho theo chặng, sản phẩm vé OD, giao dịch, dự báo nhu cầu, tối ưu doanh thu, định giá động và kiểm toán.\\r\\n4: \\r\\n5: \u003e Phạm vi hiện tại gồm bảng, ràng buộc, index và trigger tự động cập nhật `updated_at`; không có seed data hoặc view.\\r\\n6: \\r\\n7: ## 1. Tổng quan quan hệ\\r\\n8: \\r\\n9: ```mermaid\\r\\n10: erDiagram\\r\\n11:     TRAINS ||--o{ TRIPS : operates\\r\\n12:     STATIONS ||--o{ TRIPS : bounds\\r\\n13:     CALENDAR_FEATURES ||..o{ TRIPS : describes_date\\r\\n14: \\r\\n15:     TRIPS ||--o{ SEGMENTS : contains\\r\\n16:     STATIONS ||--o{ SEGMENTS : bounds\\r\\n17:     TRIPS ||--o{ SEATS : has\\r\\n18: \\r\\n19:     SEAT_TYPES ||--o{ SEATS : classifies\\r\\n20:     SEGMENTS ||--o{ SEGMENT_CAPACITIES : has\\r\\n21:     SEAT_TYPES ||--o{ SEGMENT_CAPACITIES : classifies\\r\\n22:     SEGMENT_CAPACITIES ||--o| SEGMENT_INVENTORY : tracks\\r\\n23: \\r\\n24:     TRIPS ||--o{ OD_PRODUCTS : offers\\r\\n25:     STATIONS ||--o{ OD_PRODUCTS : bounds\\r\\n26:     SEAT_TYPES ||--o{ OD_PRODUCTS : classifies\\r\\n27:     FARE_CLASSES ||--o{ OD_PRODUCTS : classifies\\r\\n28:     OD_PRODUCTS ||--o{ OD_PRODUCT_SEGMENTS : traverses\\r\\n29:     SEGMENTS ||--o{ OD_PRODUCT_SEGMENTS : belongs_to\\r\\n30: \\r\\n31:     OD_PRODUCTS ||--o{ BOOKINGS : booked_as\\r\\n32:     SEATS o|--o{ BOOKINGS : assigned_to\\r\\n33:     OD_PRODUCTS o|--o{ SEARCH_LOGS : returned_by\\r\\n34:     STATIONS ||--o{ SEARCH_LOGS : searched_between\\r\\n35:     SEAT_TYPES ||--o{ SEARCH_LOGS : requested_as\\r\\n36:     SEATS ||--o{ GAP_COMBINATIONS : yields\\r\\n37:     STATIONS ||--o{ GAP_COMBINATIONS : bounds\\r\\n38:     OD_PRODUCTS o|--o{ GAP_COMBINATIONS : suggests\\r\\n39: \\r\\n40:     OD_PRODUCTS ||--o{ DEMAND_FORECASTS : forecast_for\\r\\n41:     SEGMENTS ||--o{ BID_PRICES : priced_for\\r\\n42:     SEAT_TYPES ||--o{ BID_PRICES : classifies\\r\\n43:     OD_PRODUCTS ||--o{ QUOTAS : allocated_to\\r\\n44: \\r\\n45:     OD_PRODUCTS o|--o{ PRICE_POLICIES : governed_by\\r\\n46:     OD_PRODUCTS ||--o{ PRICE_QUOTES : quoted_for\\r\\n47:     PRICE_POLICIES o|--o{ PRICE_QUOTES : applies\\r\\n48: ```\\r\\n49: \\r\\n50: `calendar_features.service_date` có cùng miền dữ liệu với `trips.service_date` nhưng schema **không khai báo khóa ngoại** giữa hai trường; đường nét đứt trong sơ đồ chỉ biểu diễn quan hệ nghiệp vụ.\\r\\n51: \\r\\n52: ### Ký hiệu\\r\\n53: \\r\\n54: - `PK`: khóa chính.\\r\\n55: - `FK`: khóa ngoại.\\r\\n56: - `UK`: giá trị hoặc tổ hợp giá trị duy nhất.\\r\\n57: - `OD` (Origin–Destination): cặp ga đi và ga đến.\\r\\n58: - `segment`: chặng giữa hai ga liên tiếp của một chuyến tàu.\\r\\n59: - `bid price`: chi phí cơ hội của một chỗ trên một chặng.\\r\\n60: \\r\\n61: ## 2. Danh mục và lịch\\r\\n62: \\r\\n63: ### 2.1. `stations` — Danh mục ga\\r\\n64: \\r\\n65: | Trường | Kiểu | Ràng buộc / mặc định | Ý nghĩa |\\r\\n66: |---|---|---|---|\\r\\n67: | `id` | `BIGINT` | PK, identity | Định danh ga. |\\r\\n68: | `code` | `VARCHAR(20)` | NOT NULL, UNIQUE | Mã ga duy nhất. |\\r\\n69: | `name` | `VARCHAR(120)` | NOT NULL | Tên ga. |\\r\\n70: | `display_order` | `INTEGER` | NULL, `\u003e= 0` | Thứ tự hiển thị. |\\r\\n71: | `created_at` | `TIMESTAMPTZ` | NOT NULL, `CURRENT_TIMESTAMP` | Thời điểm tạo. |\\r\\n72: \\r\\n73: ### 2.2. `trains` — Danh mục tàu\\r\\n74: \\r\\n75: | Trường | Kiểu | Ràng buộc / mặc định | Ý nghĩa |\\r\\n76: |---|---|---|---|\\r\\n77: | `id` | `BIGINT` | PK, identity | Định danh tàu. |\\r\\n78: | `code` | `VARCHAR(30)` | NOT NULL, UNIQUE | Mã tàu duy nhất. |\\r\\n79: | `name` | `VARCHAR(120)` | NULL | Tên tàu. |\\r\\n80: | `is_active` | `BOOLEAN` | NOT NULL, `TRUE` | Tàu còn hoạt động hay không. |\\r\\n81: | `created_at` | `TIMESTAMPTZ` | NOT NULL, `CURRENT_TIMESTAMP` | Thời điểm tạo. |\\r\\n82: \\r\\n83: ### 2.3. `seat_types` — Danh mục loại chỗ\\r\\n84: \\r\\n85: | Trường | Kiểu | Ràng buộc / mặc định | Ý nghĩa |\\r\\n86: |---|---|---|---|\\r\\n87: | `code` | `VARCHAR(30)` | PK | Mã loại ghế/giường. |\\r\\n88: | `name` | `VARCHAR(120)` | NOT NULL | Tên loại chỗ. |\\r\\n89: | `is_active` | `BOOLEAN` | NOT NULL, `TRUE` | Loại chỗ còn được sử dụng. |\\r\\n90: | `created_at` | `TIMESTAMPTZ` | NOT NULL, `CURRENT_TIMESTAMP` | Thời điểm tạo. |\\r\\n91: \\r\\n92: Được tham chiếu bởi `seats`, `segment_capacities`, `od_products`, `search_logs` và `bid_prices`.\\r\\n93: \\r\\n94: ### 2.4. `fare_classes` — Danh mục hạng giá\\r\\n95: \\r\\n96: | Trường | Kiểu | Ràng buộc / mặc định | Ý nghĩa |\\r\\n97: |---|---|---|---|\\r\\n98: | `code` | `VARCHAR(30)` | PK | Mã hạng giá. |\\r\\n99: | `name` | `VARCHAR(120)` | NOT NULL | Tên hạng giá. |\\r\\n100: | `is_active` | `BOOLEAN` | NOT NULL, `TRUE` | Hạng giá còn được sử dụng. |\\r\\n101: | `created_at` | `TIMESTAMPTZ` | NOT NULL, `CURRENT_TIMESTAMP` | Thời điểm tạo. |\\r\\n102: \\r\\n103: `od_products.fare_class` mặc định là `standard`, vì vậy bản ghi mã `standard` phải tồn tại trước khi dùng giá trị mặc định này.\\r\\n104: \\r\\n105: ### 2.5. `calendar_features` — Đặc trưng lịch\\r\\n106: \\r\\n107: | Trường | Kiểu | Ràng buộc / mặc định | Ý nghĩa |\\r\\n108: |---|---|---|---|\\r\\n109: | `service_date` | `DATE` | PK | Ngày vận hành. |\\r\\n110: | `is_holiday` | `BOOLEAN` | NOT NULL, `FALSE` | Có phải ngày lễ. |\\r\\n111: | `is_tet` | `BOOLEAN` | NOT NULL, `FALSE` | Có thuộc dịp Tết. |\\r\\n112: | `season` | `VARCHAR(20)` | NULL | Mùa hoặc giai đoạn trong năm. |\\r\\n113: | `weather` | `VARCHAR(30)` | NULL | Nhóm thời tiết. |\\r\\n114: | `local_event` | `VARCHAR(120)` | NULL | Sự kiện địa phương. |\\r\\n115: | `created_at` | `TIMESTAMPTZ` | NOT NULL, `CURRENT_TIMESTAMP` | Thời điểm tạo. |\\r\\n116: | `updated_at` | `TIMESTAMPTZ` | NOT NULL, `CURRENT_TIMESTAMP` | Thời điểm cập nhật. |\\r\\n117: \\r\\n118: Đây là nguồn feature theo ngày cho dự báo; schema chưa ép quan hệ FK với `trips`.\\r\\n119: \\r\\n120: ## 3. Vận hành chuyến tàu và tồn kho\\r\\n121: \\r\\n122: ### 3.1. `trips` — Chuyến tàu theo ngày\\r\\n123: \\r\\n124: | Trường | Kiểu | Ràng buộc / mặc định | Ý nghĩa |\\r\\n125: |---|---|---|---|\\r\\n126: | `id` | `BIGINT` | PK, identity | Định danh chuyến. |\\r\\n127: | `train_id` | `BIGINT` | FK → `trains.id`, NOT NULL | Tàu vận hành. |\\r\\n128: | `service_date` | `DATE` | NOT NULL | Ngày chạy. |\\r\\n129: | `origin_station_id` | `BIGINT` | FK → `stations.id`, NOT NULL | Ga đầu chuyến. |\\r\\n130: | `destination_station_id` | `BIGINT` | FK → `stations.id`, NOT NULL | Ga cuối chuyến. |\\r\\n131: | `departure_at` | `TIMESTAMPTZ` | NOT NULL | Thời gian khởi hành. |\\r\\n132: | `arrival_at` | `TIMESTAMPTZ` | NOT NULL, `\u003e departure_at` | Thời gian đến. |\\r\\n133: | `status` | `VARCHAR(20)` | NOT NULL, `scheduled` | `scheduled`, `boarding`, `departed`, `completed`, `cancelled`. |\\r\\n134: | `created_at` | `TIMESTAMPTZ` | NOT NULL, `CURRENT_TIMESTAMP` | Thời điểm tạo. |\\r\\n135: | `updated_at` | `TIMESTAMPTZ` | NOT NULL, `CURRENT_TIMESTAMP` | Thời điểm cập nhật. |\\r\\n136: \\r\\n137: Ràng buộc thêm: `(train_id, service_date)` là duy nhất và ga đầu phải khác ga cuối.\\r\\n138: \\r\\n139: ### 3.2. `segments` — Chặng liên tiếp\\r\\n140: \\r\\n141: | Trường | Kiểu | Ràng buộc / mặc định | Ý nghĩa |\\r\\n142: |---|---|---|---|\\r\\n143: | `id` | `BIGINT` | PK, identity | Định danh chặng. |\\r\\n144: | `trip_id` | `BIGINT` | FK → `trips.id`, NOT NULL, ON DELETE CASCADE | Chuyến chứa chặng. |\\r\\n145: | `sequence_no` | `INTEGER` | NOT NULL, `\u003e 0` | Thứ tự chặng. |\\r\\n146: | `origin_station_id` | `BIGINT` | FK → `stations.id`, NOT NULL | Ga đầu chặng. |\\r\\n147: | `destination_station_id` | `BIGINT` | FK → `stations.id`, NOT NULL | Ga cuối chặng. |\\r\\n148: | `departure_at` | `TIMESTAMPTZ` | NOT NULL | Giờ rời ga. |\\r\\n149: | `arrival_at` | `TIMESTAMPTZ` | NOT NULL, `\u003e departure_at` | Giờ đến ga. |\\r\\n150: | `distance_km` | `NUMERIC(8,2)` | NOT NULL, `\u003e 0` | Cự ly chặng. |\\r\\n151: | `created_at` | `TIMESTAMPTZ` | NOT NULL, `CURRENT_TIMESTAMP` | Thời điểm tạo. |\\r\\n152: \\r\\n153: Mỗi chuyến có duy nhất một `sequence_no` và một cặp `(origin_station_id, destination_station_id)`; ga đầu phải khác ga cuối.\\r\\n154: \\r\\n155: ### 3.3. `seats` — Chỗ vật lý của chuyến\\r\\n156: \\r\\n157: | Trường | Kiểu | Ràng buộc / mặc định | Ý nghĩa |\\r\\n158: |---|---|---|---|\\r\\n159: | `id` | `BIGINT` | PK, identity | Định danh chỗ. |\\r\\n160: | `trip_id` | `BIGINT` | FK → `trips.id`, NOT NULL, ON DELETE CASCADE | Chuyến sở hữu chỗ. |\\r\\n161: | `coach_no` | `VARCHAR(10)` | NOT NULL | Mã toa. |\\r\\n162: | `seat_no` | `VARCHAR(10)` | NOT NULL | Mã ghế/giường trong toa. |\\r\\n163: | `seat_type` | `VARCHAR(30)` | FK → `seat_types.code`, NOT NULL | Loại chỗ. |\\r\\n164: | `status` | `VARCHAR(20)` | NOT NULL, `available` | `available`, `locked`, `maintenance`. |\\r\\n165: | `created_at` | `TIMESTAMPTZ` | NOT NULL, `CURRENT_TIMESTAMP` | Thời điểm tạo. |\\r\\n166: \\r\\n167: Tổ hợp `(trip_id, coach_no, seat_no)` là duy nhất.\\r\\n168: \\r\\n169: ### 3.4. `segment_capacities` — Sức chứa theo chặng\\r\\n170: \\r\\n171: | Trường | Kiểu | Ràng buộc / mặc định | Ý nghĩa |\\r\\n172: |---|---|---|---|\\r\\n173: | `segment_id` | `BIGINT` | PK, FK → `segments.id`, ON DELETE CASCADE | Chặng được cấu hình. |\\r\\n174: | `seat_type` | `VARCHAR(30)` | PK, FK → `seat_types.code` | Loại chỗ. |\\r\\n175: | `capacity` | `INTEGER` | NOT NULL, `\u003e= 0` | Tổng sức chứa của loại chỗ trên chặng. |\\r\\n176: | `created_at` | `TIMESTAMPTZ` | NOT NULL, `CURRENT_TIMESTAMP` | Thời điểm tạo. |\\r\\n177: | `updated_at` | `TIMESTAMPTZ` | NOT NULL, `CURRENT_TIMESTAMP` | Thời điểm cập nhật. |\\r\\n178: \\r\\n179: Khóa chính ghép là `(segment_id, seat_type)`.\\r\\n180: \\r\\n181: ### 3.5. `segment_inventory` — Tồn kho còn lại theo chặng\\r\\n182: \\r\\n183: | Trường | Kiểu | Ràng buộc / mặc định | Ý nghĩa |\\r\\n184: |---|---|---|---|\\r\\n185: | `segment_id` | `BIGINT` | PK ghép | Chặng được theo dõi. |\\r\\n186: | `seat_type` | `VARCHAR(30)` | PK ghép | Loại chỗ. |\\r\\n187: | `remaining` | `INTEGER` | NOT NULL, `\u003e= 0` | Số chỗ còn lại. |\\r\\n188: | `updated_at` | `TIMESTAMPTZ` | NOT NULL, `CURRENT_TIMESTAMP` | Thời điểm cập nhật tồn kho. |\\r\\n189: \\r\\n190: Khóa ngoại ghép `(segment_id, seat_type)` tham chiếu `segment_capacities(segment_id, seat_type)` với `ON DELETE CASCADE`. Nhờ đó chỉ có thể tạo tồn kho cho một cấu hình sức chứa đã tồn tại. Schema chưa có CHECK `remaining \u003c= capacity`; ứng dụng phải bảo đảm quy tắc này.\\r\\n191: \\r\\n192: ## 4. Sản phẩm vé và giao dịch\\r\\n193: \\r\\n194: ### 4.1. `od_products` — Sản phẩm vé OD\\r\\n195: \\r\\n196: | Trường | Kiểu | Ràng buộc / mặc định | Ý nghĩa |\\r\\n197: |---|---|---|---|\\r\\n198: | `id` | `BIGINT` | PK, identity | Định danh sản phẩm. |\\r\\n199: | `trip_id` | `BIGINT` | FK → `trips.id`, NOT NULL, ON DELETE CASCADE | Chuyến áp dụng. |\\r\\n200: | `origin_station_id` | `BIGINT` | FK → `stations.id`, NOT NULL | Ga lên tàu. |\\r\\n201: | `destination_station_id` | `BIGINT` | FK → `stations.id`, NOT NULL | Ga xuống tàu. |\\r\\n202: | `seat_type` | `VARCHAR(30)` | FK → `seat_types.code`, NOT NULL | Loại chỗ. |\\r\\n203: | `fare_class` | `VARCHAR(30)` | FK → `fare_classes.code`, NOT NULL, `standard` | Hạng giá. |\\r\\n204: | `base_price` | `NUMERIC(14,2)` | NOT NULL, `\u003e= 0` | Giá cơ sở. |\\r\\n205: | `distance_km` | `NUMERIC(8,2)` | NOT NULL, `\u003e 0` | Tổng cự ly OD. |\\r\\n206: | `is_active` | `BOOLEAN` | NOT NULL, `TRUE` | Sản phẩm đang được bán. |\\r\\n207: | `created_at` | `TIMESTAMPTZ` | NOT NULL, `CURRENT_TIMESTAMP` | Thời điểm tạo. |\\r\\n208: | `updated_at` | `TIMESTAMPTZ` | NOT NULL, `CURRENT_TIMESTAMP` | Thời điểm cập nhật. |\\r\\n209: \\r\\n210: Ga đầu phải khác ga cuối. Tổ hợp `(trip_id, origin_station_id, destination_station_id, seat_type, fare_class)` là duy nhất.\\r\\n211: \\r\\n212: ### 4.2. `od_product_segments` — Ánh xạ sản phẩm OD với chặng\\r\\n213: \\r\\n214: | Trường | Kiểu | Ràng buộc / mặc định | Ý nghĩa |\\r\\n215: |---|---|---|---|\\r\\n216: | `od_product_id` | `BIGINT` | PK, FK → `od_products.id`, ON DELETE CASCADE | Sản phẩm OD. |\\r\\n217: | `segment_id` | `BIGINT` | PK, FK → `segments.id`, ON DELETE CASCADE | Chặng mà sản phẩm đi qua. |\\r\\n218: \\r\\n219: Đây là bảng nối nhiều-nhiều. Khóa chính ghép `(od_product_id, segment_id)` ngăn trùng ánh xạ; index `ix_od_product_segments_segment` hỗ trợ truy vấn ngược từ chặng sang sản phẩm.\\r\\n220: \\r\\n221: ### 4.3. `bookings` — Đặt vé\\r\\n222: \\r\\n223: | Trường | Kiểu | Ràng buộc / mặc định | Ý nghĩa |\\r\\n224: |---|---|---|---|\\r\\n225: | `id` | `BIGINT` | PK, identity | Định danh giao dịch. |\\r\\n226: | `booking_code` | `VARCHAR(50)` | NOT NULL, UNIQUE | Mã đặt vé. |\\r\\n227: | `od_product_id` | `BIGINT` | FK → `od_products.id`, NOT NULL | Sản phẩm được mua. |\\r\\n228: | `seat_id` | `BIGINT` | FK → `seats.id`, NULL | Chỗ được gán. |\\r\\n229: | `status` | `VARCHAR(20)` | NOT NULL, `confirmed` | `held`, `confirmed`, `cancelled`, `refunded`. |\\r\\n230: | `channel` | `VARCHAR(30)` | NULL | Kênh bán. |\\r\\n231: | `booked_price` | `NUMERIC(14,2)` | NOT NULL, `\u003e= 0` | Giá đã chốt. |\\r\\n232: | `booked_at` | `TIMESTAMPTZ` | NOT NULL | Thời điểm đặt. |\\r\\n233: | `expires_at` | `TIMESTAMPTZ` | NULL, `\u003e booked_at` | Hạn giữ chỗ. |\\r\\n234: | `cancelled_at` | `TIMESTAMPTZ` | NULL, `\u003e= booked_at` | Thời điểm hủy. |\\r\\n235: | `refunded_at` | `TIMESTAMPTZ` | NULL, `\u003e= booked_at` | Thời điểm hoàn tiền. |\\r\\n236: | `created_at` | `TIMESTAMPTZ` | NOT NULL, `CURRENT_TIMESTAMP` | Thời điểm tạo. |\\r\\n237: | `updated_at` | `TIMESTAMPTZ` | NOT NULL, `CURRENT_TIMESTAMP` | Thời điểm cập nhật. |\\r\\n238: \\r\\n239: ### 4.4. `search_logs` — Nhật ký tìm kiếm\\r\\n240: \\r\\n241: | Trường | Kiểu | Ràng buộc / mặc định | Ý nghĩa |\\r\\n242: |---|---|---|---|\\r\\n243: | `id` | `BIGINT` | PK, identity | Định danh lượt tìm. |\\r\\n244: | `searched_at` | `TIMESTAMPTZ` | NOT NULL | Thời điểm tìm kiếm. |\\r\\n245: | `origin_station_id` | `BIGINT` | FK → `stations.id`, NOT NULL | Ga đi được tìm. |\\r\\n246: | `destination_station_id` | `BIGINT` | FK → `stations.id`, NOT NULL | Ga đến được tìm. |\\r\\n247: | `seat_type` | `VARCHAR(30)` | FK → `seat_types.code`, NOT NULL | Loại chỗ được yêu cầu. |\\r\\n248: | `service_date` | `DATE` | NOT NULL | Ngày chạy được tìm. |\\r\\n249: | `result` | `VARCHAR(20)` | NOT NULL | `found`, `sold_out`, `no_result`. |\\r\\n250: | `od_product_id` | `BIGINT` | FK → `od_products.id`, NULL, ON DELETE SET NULL | Sản phẩm được trả về. |\\r\\n251: | `channel` | `VARCHAR(30)` | NULL | Kênh tìm kiếm. |\\r\\n252: | `created_at` | `TIMESTAMPTZ` | NOT NULL, `CURRENT_TIMESTAMP` | Thời điểm lưu log. |\\r\\n253: \\r\\n254: Ga đi phải khác ga đến. Index `ix_search_logs_demand` hỗ trợ tổng hợp nhu cầu theo ngày, OD, loại chỗ và thời điểm tìm.\\r\\n255: \\r\\n256: ### 4.5. `gap_combinations` — Tổ hợp khoảng trống ghế\\r\\n257: \\r\\n258: | Trường | Kiểu | Ràng buộc / mặc định | Ý nghĩa |\\r\\n259: |---|---|---|---|\\r\\n260: | `id` | `BIGINT` | PK, identity | Định danh gợi ý. |\\r\\n261: | `seat_id` | `BIGINT` | FK → `seats.id`, NOT NULL, ON DELETE CASCADE | Chỗ có khoảng trống. |\\r\\n262: | `from_station_id` | `BIGINT` | FK → `stations.id`, NOT NULL | Ga đầu khoảng trống. |\\r\\n263: | `to_station_id` | `BIGINT` | FK → `stations.id`, NOT NULL | Ga cuối khoảng trống. |\\r\\n264: | `suggested_od_product_id` | `BIGINT` | FK → `od_products.id`, NULL, ON DELETE SET NULL | Sản phẩm có thể bán bù. |\\r\\n265: | `run_version` | `VARCHAR(80)` | NOT NULL | Phiên tính toán. |\\r\\n266: | `is_active` | `BOOLEAN` | NOT NULL, `TRUE` | Gợi ý hiện hành. |\\r\\n267: | `created_at` | `TIMESTAMPTZ` | NOT NULL, `CURRENT_TIMESTAMP` | Thời điểm tạo. |\\r\\n268: \\r\\n269: Ga đầu phải khác ga cuối. Tổ hợp `(seat_id, from_station_id, to_station_id, run_version)` là duy nhất; index `ix_gap_combinations_lookup` tối ưu tra cứu theo cặp ga và trạng thái.\\r\\n270: \\r\\n271: ## 5. Dự báo và tối ưu doanh thu\\r\\n272: \\r\\n273: ### 5.1. `demand_forecasts` — Dự báo nhu cầu\\r\\n274: \\r\\n275: | Trường | Kiểu | Ràng buộc / mặc định | Ý nghĩa |\\r\\n276: |---|---|---|---|\\r\\n277: | `id` | `BIGINT` | PK, identity | Định danh kết quả. |\\r\\n278: | `od_product_id` | `BIGINT` | FK → `od_products.id`, NOT NULL, ON DELETE CASCADE | Sản phẩm được dự báo. |\\r\\n279: | `forecast_at` | `TIMESTAMPTZ` | NOT NULL | Thời điểm dự báo. |\\r\\n280: | `lead_days` | `INTEGER` | NOT NULL, `\u003e= 0` | Số ngày trước ngày chạy. |\\r\\n281: | `demand_point` | `NUMERIC(12,3)` | NOT NULL, `\u003e= 0` | Dự báo điểm. |\\r\\n282: | `demand_p10` | `NUMERIC(12,3)` | NULL, `\u003e= 0` | Phân vị 10%. |\\r\\n283: | `demand_p50` | `NUMERIC(12,3)` | NULL, `\u003e= 0` | Phân vị 50%. |\\r\\n284: | `demand_p90` | `NUMERIC(12,3)` | NULL, `\u003e= 0` | Phân vị 90%. |\\r\\n285: | `model_version` | `VARCHAR(80)` | NULL | Phiên bản mô hình. |\\r\\n286: | `created_at` | `TIMESTAMPTZ` | NOT NULL, `CURRENT_TIMESTAMP` | Thời điểm lưu. |\\r\\n287: \\r\\n288: Các phân vị không âm và phải thỏa `p10 \u003c= p50 \u003c= p90` khi các cặp liên quan cùng có giá trị. Tổ hợp `(od_product_id, forecast_at, lead_days)` là duy nhất.\\r\\n289: \\r\\n290: ### 5.2. `bid_prices` — Chi phí cơ hội theo chặng\\r\\n291: \\r\\n292: | Trường | Kiểu | Ràng buộc / mặc định | Ý nghĩa |\\r\\n293: |---|---|---|---|\\r\\n294: | `id` | `BIGINT` | PK, identity | Định danh kết quả. |\\r\\n295: | `segment_id` | `BIGINT` | FK → `segments.id`, NOT NULL, ON DELETE CASCADE | Chặng được định giá. |\\r\\n296: | `seat_type` | `VARCHAR(30)` | FK → `seat_types.code`, NOT NULL | Loại chỗ. |\\r\\n297: | `bid_price` | `NUMERIC(14,2)` | NOT NULL, `\u003e= 0` | Chi phí cơ hội. |\\r\\n298: | `remaining_capacity` | `INTEGER` | NOT NULL, `\u003e= 0` | Sức chứa còn lại lúc tính. |\\r\\n299: | `calculated_at` | `TIMESTAMPTZ` | NOT NULL | Thời điểm tính. |\\r\\n300: | `run_version` | `VARCHAR(80)` | NOT NULL | Phiên tối ưu. |\\r\\n301: | `is_active` | `BOOLEAN` | NOT NULL, `TRUE` | Kết quả hiện hành. |\\r\\n302: | `created_at` | `TIMESTAMPTZ` | NOT NULL, `CURRENT_TIMESTAMP` | Thời điểm lưu. |\\r\\n303: \\r\\n304: Tổ hợp `(segment_id, seat_type, run_version)` là duy nhất. Partial unique index `ux_bid_prices_active` chỉ cho phép một bản ghi `is_active = TRUE` trên mỗi `(segment_id, seat_type)`.\\r\\n305: \\r\\n306: ### 5.3. `quotas` — Hạn ngạch bán\\r\\n307: \\r\\n308: | Trường | Kiểu | Ràng buộc / mặc định | Ý nghĩa |\\r\\n309: |---|---|---|---|\\r\\n310: | `id` | `BIGINT` | PK, identity | Định danh hạn ngạch. |\\r\\n311: | `od_product_id` | `BIGINT` | FK → `od_products.id`, NOT NULL, ON DELETE CASCADE | Sản phẩm nhận hạn ngạch. |\\r\\n312: | `quota` | `INTEGER` | NOT NULL, `\u003e= 0` | Số chỗ được phân bổ. |\\r\\n313: | `calculated_at` | `TIMESTAMPTZ` | NOT NULL | Thời điểm tính. |\\r\\n314: | `run_version` | `VARCHAR(80)` | NOT NULL | Phiên tối ưu. |\\r\\n315: | `is_active` | `BOOLEAN` | NOT NULL, `TRUE` | Hạn ngạch hiện hành. |\\r\\n316: | `created_at` | `TIMESTAMPTZ` | NOT NULL, `CURRENT_TIMESTAMP` | Thời điểm lưu. |\\r\\n317: \\r\\n318: Tổ hợp `(od_product_id, run_version)` là duy nhất. Partial unique index `ux_quotas_active` chỉ cho phép một hạn ngạch đang hoạt động cho mỗi sản phẩm OD.\\r\\n319: \\r\\n320: ## 6. Chính sách và định giá động\\r\\n321: \\r\\n322: ### 6.1. `price_policies` — Chính sách kiểm soát giá\\r\\n323: \\r\\n324: | Trường | Kiểu | Ràng buộc / mặc định | Ý nghĩa |\\r\\n325: |---|---|---|---|\\r\\n326: | `id` | `BIGINT` | PK, identity | Định danh chính sách. |\\r\\n327: | `od_product_id` | `BIGINT` | FK → `od_products.id`, NULL, ON DELETE CASCADE | Sản phẩm áp dụng; NULL cho chính sách chung. |\\r\\n328: | `name` | `VARCHAR(120)` | NOT NULL | Tên chính sách. |\\r\\n329: | `min_price` | `NUMERIC(14,2)` | NOT NULL, `\u003e= 0` | Giá sàn. |\\r\\n330: | `max_price` | `NUMERIC(14,2)` | NOT NULL, `\u003e= min_price` | Giá trần. |\\r\\n331: | `max_step_change` | `NUMERIC(14,2)` | NOT NULL, `\u003e= 0` | Biến động tối đa mỗi bước. |\\r\\n332: | `valid_from` | `TIMESTAMPTZ` | NOT NULL | Bắt đầu hiệu lực. |\\r\\n333: | `valid_to` | `TIMESTAMPTZ` | NULL, `\u003e valid_from` | Kết thúc hiệu lực. |\\r\\n334: | `status` | `VARCHAR(20)` | NOT NULL, `draft` | `draft`, `active`, `inactive`. |\\r\\n335: | `created_by` | `VARCHAR(120)` | NULL | Người tạo. |\\r\\n336: | `approved_by` | `VARCHAR(120)` | NULL | Người phê duyệt. |\\r\\n337: | `created_at` | `TIMESTAMPTZ` | NOT NULL, `CURRENT_TIMESTAMP` | Thời điểm tạo. |\\r\\n338: | `updated_at` | `TIMESTAMPTZ` | NOT NULL, `CURRENT_TIMESTAMP` | Thời điểm cập nhật. |\\r\\n339: \\r\\n340: ### 6.2. `price_quotes` — Kết quả báo giá động\\r\\n341: \\r\\n342: | Trường | Kiểu | Ràng buộc / mặc định | Ý nghĩa |\\r\\n343: |---|---|---|---|\\r\\n344: | `id` | `BIGINT` | PK, identity | Định danh báo giá. |\\r\\n345: | `od_product_id` | `BIGINT` | FK → `od_products.id`, NOT NULL | Sản phẩm được báo giá. |\\r\\n346: | `policy_id` | `BIGINT` | FK → `price_policies.id`, NULL | Chính sách đã áp dụng. |\\r\\n347: | `opportunity_cost` | `NUMERIC(14,2)` | NOT NULL, `\u003e= 0` | Tổng chi phí cơ hội. |\\r\\n348: | `proposed_price` | `NUMERIC(14,2)` | NOT NULL, `\u003e= 0` | Giá thuật toán đề xuất. |\\r\\n349: | `final_price` | `NUMERIC(14,2)` | NOT NULL, `\u003e= 0` | Giá sau Policy Guard. |\\r\\n350: | `decision` | `VARCHAR(20)` | NOT NULL | `accepted`, `rejected`, `blocked`. |\\r\\n351: | `explanation` | `JSONB` | NOT NULL, `{}` | Dữ liệu giải thích. |\\r\\n352: | `run_version` | `VARCHAR(80)` | NULL | Phiên thuật toán. |\\r\\n353: | `quoted_at` | `TIMESTAMPTZ` | NOT NULL, `CURRENT_TIMESTAMP` | Thời điểm báo giá. |\\r\\n354: | `expires_at` | `TIMESTAMPTZ` | NULL, `\u003e quoted_at` | Hạn báo giá. |\\r\\n355: | `confirmed_at` | `TIMESTAMPTZ` | NULL, `\u003e= quoted_at` | Thời điểm xác nhận. |\\r\\n356: | `created_at` | `TIMESTAMPTZ` | NOT NULL, `CURRENT_TIMESTAMP` | Thời điểm lưu. |\\r\\n357: \\r\\n358: ## 7. Kiểm toán\\r\\n359: \\r\\n360: ### 7.1. `audit_logs` — Nhật ký thay đổi\\r\\n361: \\r\\n362: | Trường | Kiểu | Ràng buộc / mặc định | Ý nghĩa |\\r\\n363: |---|---|---|---|\\r\\n364: | `id` | `BIGINT` | PK, identity | Định danh log. |\\r\\n365: | `actor` | `VARCHAR(120)` | NOT NULL | Người dùng hoặc dịch vụ thực hiện. |\\r\\n366: | `action` | `VARCHAR(60)` | NOT NULL | Hành động. |\\r\\n367: | `entity_type` | `VARCHAR(60)` | NOT NULL | Loại đối tượng. |\\r\\n368: | `entity_id` | `VARCHAR(80)` | NULL | ID đối tượng dưới dạng chuỗi. |\\r\\n369: | `before_data` | `JSONB` | NULL | Trạng thái trước thay đổi. |\\r\\n370: | `after_data` | `JSONB` | NULL | Trạng thái sau thay đổi. |\\r\\n371: | `created_at` | `TIMESTAMPTZ` | NOT NULL, `CURRENT_TIMESTAMP` | Thời điểm hành động. |\\r\\n372: \\r\\n373: `audit_logs` dùng tham chiếu mềm qua `entity_type` và `entity_id`, không có FK tới các bảng nghiệp vụ.\\r\\n374: \\r\\n375: ## 8. Index tường minh\\r\\n376: \\r\\n377: | Index | Bảng / cột | Loại | Mục đích |\\r\\n378: |---|---|---|---|\\r\\n379: | `ux_bid_prices_active` | `bid_prices(segment_id, seat_type)` WHERE `is_active = TRUE` | UNIQUE, partial | Mỗi chặng và loại chỗ chỉ có một bid price hiện hành. |\\r\\n380: | `ux_quotas_active` | `quotas(od_product_id)` WHERE `is_active = TRUE` | UNIQUE, partial | Mỗi sản phẩm chỉ có một quota hiện hành. |\\r\\n381: | `ix_search_logs_demand` | `search_logs(service_date, origin_station_id, destination_station_id, seat_type, searched_at)` | Thường | Phân tích nhu cầu tìm kiếm theo ngày và OD. |\\r\\n382: | `ix_od_product_segments_segment` | `od_product_segments(segment_id, od_product_id)` | Thường | Tra các sản phẩm đi qua một chặng. |\\r\\n383: | `ix_gap_combinations_lookup` | `gap_combinations(from_station_id, to_station_id, is_active)` | Thường | Tra gợi ý lấp khoảng trống theo OD. |\\r\\n384: \\r\\n385: Ngoài 5 index trên, PostgreSQL tự tạo index để thực thi các `PRIMARY KEY` và `UNIQUE` constraint. Schema không tự tạo index cho mọi khóa ngoại.\\r\\n386: \\r\\n387: ## 9. Trigger tự động cập nhật `updated_at`\\r\\n388: \\r\\n389: Function `set_updated_at()` chạy trước mỗi lệnh `UPDATE`, gán `NEW.updated_at = CURRENT_TIMESTAMP` rồi trả về bản ghi mới. Bảy trigger mức dòng (`FOR EACH ROW`) dùng chung function này:\\r\\n390: \\r\\n391: | Trigger | Bảng | Thời điểm |\\r\\n392: |---|---|---|\\r\\n393: | `trg_calendar_features_updated_at` | `calendar_features` | `BEFORE UPDATE` |\\r\\n394: | `trg_trips_updated_at` | `trips` | `BEFORE UPDATE` |\\r\\n395: | `trg_segment_capacities_updated_at` | `segment_capacities` | `BEFORE UPDATE` |\\r\\n396: | `trg_segment_inventory_updated_at` | `segment_inventory` | `BEFORE UPDATE` |\\r\\n397: | `trg_od_products_updated_at` | `od_products` | `BEFORE UPDATE` |\\r\\n398: | `trg_bookings_updated_at` | `bookings` | `BEFORE UPDATE` |\\r\\n399: | `trg_price_policies_updated_at` | `price_policies` | `BEFORE UPDATE` |\\r\\n400: \\r\\n401: Mỗi lệnh UPDATE trên các bảng này sẽ làm mới `updated_at`, kể cả khi ứng dụng truyền một giá trị khác cho trường đó. Các bảng không có cột `updated_at` không được gắn trigger.\\r\\n402: \\r\\n403: ## 10. Luồng dữ liệu chính\\r\\n404: \\r\\n405: 1. `stations`, `trains`, `seat_types`, `fare_classes` và `calendar_features` cung cấp dữ liệu danh mục và đặc trưng lịch.\\r\\n406: 2. `trips`, `segments` và `seats` mô tả chuyến cùng sơ đồ chỗ; `segment_capacities` và `segment_inventory` quản lý sức chứa theo từng chặng và loại chỗ.\\r\\n407: 3. `od_products` định nghĩa vé bán được; `od_product_segments` chỉ rõ từng sản phẩm chiếm những chặng nào.\\r\\n408: 4. `search_logs` ghi nhận nhu cầu tiềm năng, `bookings` ghi nhận nhu cầu đã chuyển đổi, còn `gap_combinations` lưu cơ hội bán bù các khoảng ghế trống.\\r\\n409: 5. Mô hình dự báo ghi kết quả vào `demand_forecasts`; bộ tối ưu tạo `bid_prices` và `quotas` từ nhu cầu và tồn kho.\\r\\n410: 6. Bộ định giá tạo `price_quotes` trong giới hạn của `price_policies`; các thay đổi quan trọng được ghi vào `audit_logs`.\\r\\n411: \\r\\n412: ## 11. Lưu ý toàn vẹn dữ liệu\\r\\n413: \\r\\n414: - Schema chưa kiểm tra ga/chặng/sản phẩm OD có thực sự thuộc đúng cùng một chuyến và đúng thứ tự hành trình; tầng ứng dụng hoặc migration bổ sung phải bảo đảm điều này.\\r\\n415: - Schema chưa kiểm tra `bookings.seat_id` thuộc cùng chuyến với `od_product_id`.\\r\\n416: - Schema chưa tự đồng bộ `segment_inventory.remaining` khi booking thay đổi và chưa ép `remaining \u003c= capacity`.\\r\\n417: - `updated_at` nhận `CURRENT_TIMESTAMP` lúc INSERT và được 7 trigger nói trên tự động làm mới lúc UPDATE.\\r\\n418: - Các FK không ghi `ON DELETE` dùng hành vi mặc định `NO ACTION`; chỉ các quan hệ được ghi rõ mới dùng `CASCADE` hoặc `SET NULL`.\\r\\n419: \\nThe above content shows the entire, complete file contents of the requested file.\\n\"}"}
