import psycopg

def get_db_url():
    with open(".env", "r") as f:
        for line in f:
            if line.startswith("DATABASE_URL="):
                val = line.split("=", 1)[1].strip()
                if val.startswith('"') and val.endswith('"'):
                    val = val[1:-1]
                return val
    raise Exception("DATABASE_URL not found in .env")

def check_data():
    db_url = get_db_url()
    conn_str = db_url.replace("REDACTEDql+psycopg://", "REDACTEDql://")

    tables = [
        "stations", "trains", "seat_types", "fare_classes",
        "calendar_features", "trips", "segments", "seats",
        "segment_capacities", "segment_inventory", "od_products",
        "od_product_segments", "bookings", "search_logs",
        "gap_combinations", "demand_forecasts", "bid_prices",
        "quotas", "price_policies", "price_quotes", "audit_logs"
    ]

    print("🔄 Connecting to AWS RDS PostgreSQL...")
    with psycopg.connect(conn_str) as conn:
        with conn.cursor() as cur:
            print("\n📊 Checking record counts in all tables:")
            has_data = False
            for table in tables:
                try:
                    cur.execute(f"SELECT COUNT(*) FROM {table}")
                    count = cur.fetchone()[0]
                    print(f"  - {table:25}: {count} records")
                    if count > 0:
                        has_data = True
                except Exception as e:
                    print(f"  - {table:25}: ERROR checking count: {e}")
                    conn.rollback() # Rollback on error to keep connection active

            if has_data:
                print("\n✅ Seed data is indeed present in the database!")
            else:
                print("\n❌ The database is completely empty.")

if __name__ == "__main__":
    check_data()

