d_at\\r\\n35:         TIMESTAMPTZ updated_at\\r\\n36:     }\\r\\n37: \\r\\n38:     SEGMENTS {\\r\\n39:         BIGINT id PK\\r\\n40:         BIGINT trip_id FK\\r\\n41:         INTEGER sequence_no\\r\\n42:         BIGINT origin_station_id FK\\r\\n43:         BIGINT destination_station_id FK\\r\\n44:         TIMESTAMPTZ departure_at\\r\\n45:         TIMESTAMPTZ arrival_at\\r\\n46:         NUMERIC_8_2 distance_km\\r\\n47:         TIMESTAMPTZ created_at\\r\\n48:     }\\r\\n49: \\r\\n50:     SEATS {\\r\\n51:         BIGINT id PK\\r\\n52:         BIGINT trip_id FK\\r\\n53:         VARCHAR_10 coach_no\\r\\n54:         VARCHAR_10 seat_no\\r\\n55:         VARCHAR_30 seat_type\\r\\n56:         VARCHAR_20 status\\r\\n57:         TIMESTAMPTZ created_at\\r\\n58:     }\\r\\n59: \\r\\n60:     OD_PRODUCTS {\\r\\n61:         BIGINT id PK\\r\\n62:         BIGINT trip_id FK\\r\\n63:         BIGINT origin_station_id FK\\r\\n64:         BIGINT destination_station_id FK\\r\\n65:         VARCHAR_30 seat_type\\r\\n66:         VARCHAR_30 fare_class\\r\\n67:         NUMERIC_14_2 base_price\\r\\n68:         NUMERIC_8_2 distance_km\\r\\n69:         BOOLEAN is_active\\r\\n70:         TIMESTAMPTZ created_at\\r\\n71:         TIMESTAMPTZ updated_at\\r\\n72:     }\\r\\n73: \\r\\n74:     BOOKINGS {\\r\\n75:         BIGINT id PK\\r\\n76:         VARCHAR_50 booking_code UK\\r\\n77:         BIGINT od_product_id FK\\r\\n78:         BIGINT seat_id FK\\r\\n79:         VARCHAR_20 status\\r\\n80:         VARCHAR_30 channel\\r\\n81:         NUMERIC_14_2 booked_price\\r\\n82:         TIMESTAMPTZ booked_at\\r\\n83:         TIMESTAMPTZ cancelled_at\\r\\n84:         TIMESTAMPTZ refunded_at\\r\\n85:         TIMESTAMPTZ created_at\\r\\n86:         TIMESTAMPTZ updated_at\\r\\n87:     }\\r\\n88: \\r\\n89:     DEMAND_FORECASTS {\\r\\n90:         BIGINT id PK\\r\\n91:         BIGINT od_product_id FK\\r\\n92:         TIMESTAMPTZ forecast_at\\r\\n93:         INTEGER lead_days\\r\\n94:         NUMERIC_12_3 demand_point\\r\\n95:         NUMERIC_12_3 demand_p10\\r\\n96:         NUMERIC_12_3 demand_p50\\r\\n97:         NUMERIC_12_3 demand_p90\\r\\n98:         VARCHAR_80 model_version\\r\\n99:         TIMESTAMPTZ created_at\\r\\n100:     }\\r\\n101: \\r\\n102:     BID_PRICES {\\r\\n103:         BIGINT id PK\\r\\n104:         BIGINT segment_id FK\\r\\n105:         VARCHAR_30 seat_type\\r\\n106:         NUMERIC_14_2 bid_price\\r\\n107:         INTEGER remaining_capacity\\r\\n108:         TIMESTAMPTZ calculated_at\\r\\n109:         VARCHAR_80 run_version\\r\\n110:         BOOLEAN is_active\\r\\n111:         TIMESTAMPTZ created_at\\r\\n112:     }\\r\\n113: \\r\\n114:     QUOTAS {\\r\\n115:         BIGINT id PK\\r\\n116:         BIGINT od_product_id FK\\r\\n117:         INTEGER quota\\r\\n118:         TIMESTAMPTZ calculated_at\\r\\n119:         VARCHAR_80 run_version\\r\\n120:         BOOLEAN is_active\\r\\n121:         TIMESTAMPTZ created_at\\r\\n122:     }\\r\\n123: \\r\\n124:     PRICE_POLICIES {\\r\\n125:         BIGINT id PK\\r\\n126:         BIGINT od_product_id FK\\r\\n127:         VARCHAR_120 name\\r\\n128:         NUMERIC_14_2 min_price\\r\\n129:         NUMERIC_14_2 max_price\\r\\n130:         NUMERIC_14_2 max_step_change\\r\\n131:         TIMESTAMPTZ valid_from\\r\\n132:         TIMESTAMPTZ valid_to\\r\\n133:         VARCHAR_20 status\\r\\n134:         VARCHAR_120 created_by\\r\\n135:         VARCHAR_120 approved_by\\r\\n136:         TIMESTAMPTZ created_at\\r\\n137:         TIMESTAMPTZ updated_at\\r\\n138:     }\\r\\n139: \\r\\n140:     PRICE_QUOTES {\\r\\n141:         BIGINT id PK\\r\\n142:         BIGINT od_product_id FK\\r\\n143:         BIGINT policy_id FK\\r\\n144:         NUMERIC_14_2 opportunity_cost\\r\\n145:         NUMERIC_14_2 proposed_price\\r\\n146:         NUMERIC_14_2 final_price\\r\\n147:         VARCHAR_20 decision\\r\\n148:         JSONB explanation\\r\\n149:         VARCHAR_80 run_version\\r\\n150:         TIMESTAMPTZ quoted_at\\r\\n151:         TIMESTAMPTZ expires_at\\r\\n152:         TIMESTAMPTZ confirmed_at\\r\\n153:         TIMESTAMPTZ created_at\\r\\n154:     }\\r\\n155: \\r\\n156:     AUDIT_LOGS {\\r\\n157:         BIGINT id PK\\r\\n158:         VARCHAR_120 actor\\r\\n159:         VARCHAR_60 action\\r\\n160:         VARCHAR_60 entity_type\\r\\n161:         VARCHAR_80 entity_id\\r\\n162:         JSONB before_data\\r\\n163:         JSONB after_data\\r\\n164:         TIMESTAMPTZ created_at\\r\\n165:     }\\r\\n166: \\r\\n167:     TRAINS ||--o{ TRIPS : \\\"có các chuyến\\\"\\r\\n168:     STATIONS ||--o{ TRIPS : \\\"ga đầu hoặc cuối\\\"\\r\\n169:     TRIPS ||--o{ SEGMENTS : \\\"được chia thành\\\"\\r\\n170:     STATIONS ||--o{ SEGMENTS : \\\"ga đầu hoặc cuối\\\"\\r\\n171:     TRIPS ||--o{ SEATS : \\\"có sơ đồ ghế\\\"\\r\\n172:     TRIPS ||--o{ OD_PRODUCTS : \\\"mở bán\\\"\\r\\n173:     STATIONS ||--o{ OD_PRODUCTS : \\\"xác định OD\\\"\\r\\n174:     OD_PRODUCTS ||--o{ BOOKINGS : \\\"được đặt\\\"\\r\\n175:     SEATS o|--o{ BOOKINGS : \\\"được gán\\\"\\r\\n176:     OD_PRODUCTS ||--o{ DEMAND_FORECASTS : \\\"được dự báo\\\"\\r\\n177:     SEGMENTS ||--o{ BID_PRICES : \\\"có chi phí cơ hội\\\"\\r\\n178:     OD_PRODUCTS ||--o{ QUOTAS : \\\"có hạn ngạch\\\"\\r\\n179:     OD_PRODUCTS o|--o{ PRICE_POLICIES : \\\"áp dụng chính sách\\\"\\r\\n180:     OD_PRODUCTS ||--o{ PRICE_QUOTES : \\\"được báo giá\\\"\\r\\n181:     PRICE_POLICIES o|--o{ PRICE_QUOTES : \\\"kiểm soát giá\\\"\\r\\n182: ```\\r\\n183: \\r\\n184: ### Ký hiệu\\r\\n185: \\r\\n186: - `PK`: khóa chính.\\r\\n187: - `FK`: khóa ngoại.\\r\\n188: - `UK`: giá trị hoặc tổ hợp giá trị duy nhất.\\r\\n189: - `OD` (Origin–Destination): cặp ga đi và ga đến.\\r\\n190: - `segment`: chặng giữa hai ga liên tiếp của một chuyến tàu.\\r\\n191: - `bid price`: chi phí cơ hội của một chỗ trên một chặng.\\r\\n192: \\r\\n193: ## 2. Nhóm dữ liệu vận hành đường sắt\\r\\n194: \\r\\n195: ### 2.1. `stations` — Danh mục ga\\r\\n196: \\r\\n197: Lưu danh sách ga được sử dụng trong MVP. Đây là bảng danh mục gốc để xác định ga đầu, ga cuối của chuyến, chặng và sản phẩm OD.\\r\\n198: \\r\\n199: | Field | Kiểu dữ liệu | Ràng buộc | Ý nghĩa |\\r\\n200: |---|---|---|---|\\r\\n201: | `id` | `BIGINT` | PK, tự tăng | Định danh nội bộ của ga. |\\r\\n202: | `code` | `VARCHAR(20)` | NOT NULL, UNIQUE | Mã ga dùng khi trao đổi dữ liệu và gọi API. |\\r\\n203: | `name` | `VARCHAR(120)` | NOT NULL | Tên hiển thị của ga. |\\r\\n204: | `display_order` | `INTEGER` | Có thể null, `\u003e= 0` | Thứ tự mặc định của ga trên tuyến để hỗ trợ sắp xếp giao diện. |\\r\\n205: | `created_at` | `TIMESTAMPTZ` | NOT NULL, mặc định thời điểm hiện tại | Thời điểm tạo bản ghi. |\\r\\n206: \\r\\n207: **Tác dụng:** tránh lặp lại tên và mã ga ở nhiều bảng, đồng thời bảo đảm chuyến, chặng và OD cùng tham chiếu một danh mục ga thống nhất.\\r\\n208: \\r\\n209: ### 2.2. `trains` — Danh mục tàu\\r\\n210: \\r\\n211: Lưu mã tàu hoặc dịch vụ tàu, ví dụ SE1, SE2. Một tàu có thể phát sinh nhiều chuyến chạy ở các ngày khác nhau.\\r\\n212: \\r\\n213: | Field | Kiểu dữ liệu | Ràng buộc | Ý nghĩa |\\r\\n214: |---|---|---|---|\\r\\n215: | `id` | `BIGINT` | PK, tự tăng | Định danh nội bộ của tàu. |\\r\\n216: | `code` | `VARCHAR(30)` | NOT NULL, UNIQUE | Mã tàu duy nhất. |\\r\\n217: | `name` | `VARCHAR(120)` | Có thể null | Tên mô tả của tàu. |\\r\\n218: | `is_active` | `BOOLEAN` | NOT NULL, mặc định `TRUE` | Cho biết tàu còn được sử dụng trong phạm vi hệ thống hay không. |\\r\\n219: | `created_at` | `TIMESTAMPTZ` | NOT NULL, mặc định thời điểm hiện tại | Thời điểm tạo bản ghi. |\\r\\n220: \\r\\n221: **Tác dụng:** tách định danh tàu khỏi từng ngày chạy, giúp cùng một mã tàu được tái sử dụng cho nhiều `trips`.\\r\\n222: \\r\\n223: ### 2.3. `trips` — Chuyến tàu theo ngày\\r\\n224: \\r\\n225: Đại diện cho một lần chạy cụ thể của một tàu vào một ngày. Đây là thực thể trung tâm kết nối hành trình, ghế và các sản phẩm vé.\\r\\n226: \\r\\n227: | Field | Kiểu dữ liệu | Ràng buộc | Ý nghĩa |\\r\\n228: |---|---|---|---|\\r\\n229: | `id` | `BIGINT` | PK, tự tăng | Định danh chuyến. |\\r\\n230: | `train_id` | `BIGINT` | FK → `trains.id`, NOT NULL | Tàu thực hiện chuyến. |\\r\\n231: | `service_date` | `DATE` | NOT NULL | Ngày chạy của chuyến. |\\r\\n232: | `origin_station_id` | `BIGINT` | FK → `stations.id`, NOT NULL | Ga đầu toàn hành trình. |\\r\\n233: | `destination_station_id` | `BIGINT` | FK → `stations.id`, NOT NULL | Ga cuối toàn hành trình. |\\r\\n234: | `departure_at` | `TIMESTAMPTZ` | NOT NULL | Thời điểm khởi hành. |\\r\\n235: | `arrival_at` | `TIMESTAMPTZ` | NOT NULL, sau `departure_at` | Thời điểm kết thúc hành trình. |\\r\\n236: | `status` | `VARCHAR(20)` | NOT NULL | Trạng thái: `scheduled`, `boarding`, `departed`, `completed`, `cancelled`. |\\r\\n237: | `created_at` | `TIMESTAMPTZ` | NOT NULL | Thời điểm tạo bản ghi. |\\r\\n238: | `updated_at` | `TIMESTAMPTZ` | NOT NULL | Thời điểm cập nhật gần nhất, do ứng dụng quản lý. |\\r\\n239: \\r\\n240: Tổ hợp `(train_id, service_date)` là duy nhất.\\r\\n241: \\r\\n242: **Tác dụng:** gom mọi dữ liệu của một lần chạy vào cùng một phạm vi để dashboard có thể lọc theo tàu và ngày.\\r\\n243: \\r\\n244: ### 2.4. `segments` — Các chặng liên tiếp\\r\\n245: \\r\\n246: Chia một `trip` thành các chặng giữa hai ga liên tiếp. Bid price và tải chặng được tính ở cấp này.\\r\\n247: \\r\\n248: | Field | Kiểu dữ liệu | Ràng buộc | Ý nghĩa |\\r\\n249: |---|---|---|---|\\r\\n250: | `id` | `BIGINT` | PK, tự tăng | Định danh chặng. |\\r\\n251: | `trip_id` | `BIGINT` | FK → `trips.id`, NOT NULL, CASCADE DELETE | Chuyến chứa chặng. |\\r\\n252: | `sequence_no` | `INTEGER` | NOT NULL, `\u003e 0` | Thứ tự chặng trong hành trình. |\\r\\n253: | `origin_station_id` | `BIGINT` | FK → `stations.id`, NOT NULL | Ga đầu chặng. |\\r\\n254: | `destination_station_id` | `BIGINT` | FK → `stations.id`, NOT NULL | Ga cuối chặng. |\\r\\n255: | `departure_at` | `TIMESTAMPTZ` | NOT NULL | Giờ rời ga đầu chặng. |\\r\\n256: | `arrival_at` | `TIMESTAMPTZ` | NOT NULL, sau `departure_at` | Giờ đến ga cuối chặng. |\\r\\n257: | `distance_km` | `NUMERIC(8,2)` | NOT NULL, `\u003e 0` | Chiều dài chặng tính theo kilomet. |\\r\\n258: | `created_at` | `TIMESTAMPTZ` | NOT NULL | Thời điểm tạo bản ghi. |\\r\\n259: \\r\\n260: Mỗi chuyến không được có hai chặng cùng `sequence_no` hoặc cùng cặp ga đầu–ga cuối.\\r\\n261: \\r\\n262: **Tác dụng:** cung cấp đơn vị nhỏ nhất để tính tải, sức chứa còn lại, nút cổ chai và chi phí cơ hội. Một OD dài có thể đi qua nhiều chặng.\\r\\n263: \\r\\n264: ### 2.5. `seats` — Ghế hoặc giường của chuyến\\r\\n265: \\r\\n266: Lưu sơ đồ chỗ vật lý cho từng chuyến, bao gồm toa, số chỗ, loại chỗ và trạng thái vận hành.\\r\\n267: \\r\\n268: | Field | Kiểu dữ liệu | Ràng buộc | Ý nghĩa |\\r\\n269: |---|---|---|---|\\r\\n270: | `id` | `BIGINT` | PK, tự tăng | Định danh chỗ vật lý. |\\r\\n271: | `trip_id` | `BIGINT` | FK → `trips.id`, NOT NULL, CASCADE DELETE | Chuyến sở hữu chỗ. |\\r\\n272: | `coach_no` | `VARCHAR(10)` | NOT NULL | Số hoặc mã toa. |\\r\\n273: | `seat_no` | `VARCHAR(10)` | NOT NULL | Số hoặc mã ghế/giường trong toa. |\\r\\n274: | `seat_type` | `VARCHAR(30)` | NOT NULL | Loại chỗ, ví dụ ngồi mềm hoặc giường nằm khoang 6. |\\r\\n275: | `status` | `VARCHAR(20)` | NOT NULL | Trạng thái: `available`, `locked`, `maintenance`. |\\r\\n276: | `created_at` | `TIMESTAMPTZ` | NOT NULL | Thời điểm tạo bản ghi. |\\r\\n277: \\r\\n278: Tổ hợp `(trip_id, coach_no, seat_no)` là duy nhất.\\r\\n279: \\r\\n280: **Tác dụng:** phục vụ gán ghế vật lý, kiểm tra ghế khóa và phát hiện các khoảng ghế còn trống giữa những OD đã bán.\\r\\n281: \\r\\n282: ## 3. Nhóm sản phẩm vé và giao dịch\\r\\n283: \\r\\n284: ### 3.1. `od_products` — Sản phẩm vé OD\\r\\n285: \\r\\n286: Mỗi bản ghi là một sản phẩm có thể bán trên một chuyến: đi từ ga A đến ga B, theo loại chỗ và hạng vé cụ thể.\\r\\n287: \\r\\n288: | Field | Kiểu dữ liệu | Ràng buộc | Ý nghĩa |\\r\\n289: |---|---|---|---|\\r\\n290: | `id` | `BIGINT` | PK, tự tăng | Định danh sản phẩm OD. |\\r\\n291: | `trip_id` | `BIGINT` | FK → `trips.id`, NOT NULL, CASCADE DELETE | Chuyến áp dụng. |\\r\\n292: | `origin_station_id` | `BIGINT` | FK → `stations.id`, NOT NULL | Ga hành khách lên tàu. |\\r\\n293: | `destination_station_id` | `BIGINT` | FK → `stations.id`, NOT NULL | Ga hành khách xuống tàu. |\\r\\n294: | `seat_type` | `VARCHAR(30)` | NOT NULL | Loại chỗ của sản phẩm. |\\r\\n295: | `fare_class` | `VARCHAR(30)` | NOT NULL, mặc định `standard` | Hạng giá như tiết kiệm, tiêu chuẩn hoặc linh hoạt. |\\r\\n296: | `base_price` | `NUMERIC(14,2)` | NOT NULL, `\u003e= 0` | Giá cơ sở trước tối ưu và ràng buộc giá. |\\r\\n297: | `distance_km` | `NUMERIC(8,2)` | NOT NULL, `\u003e 0` | Tổng cự ly của OD. |\\r\\n298: | `is_active` | `BOOLEAN` | NOT NULL | Cho biết sản phẩm đang được phép bán. |\\r\\n299: | `created_at` | `TIMESTAMPTZ` | NOT NULL | Thời điểm tạo bản ghi. |\\r\\n300: | `updated_at` | `TIMESTAMPTZ` | NOT NULL | Thời điểm cập nhật gần nhất. |\\r\\n301: \\r\\n302: Tổ hợp `(trip_id, origin_station_id, destination_station_id, seat_type, fare_class)` là duy nhất.\\r\\n303: \\r\\n304: **Tác dụng:** là điểm nối chung cho dự báo, quota, báo giá và booking. Nhờ đó các kết quả AI đều tham chiếu đúng một sản phẩm bán cụ thể.\\r\\n305: \\r\\n306: ### 3.2. `bookings` — Đặt vé\\r\\n307: \\r\\n308: Lưu giao dịch giữ chỗ, xác nhận mua, hủy hoặc hoàn vé. Dữ liệu này là đầu vào để tính tải chặng, doanh thu và cập nhật dự báo.\\r\\n309: \\r\\n310: | Field | Kiểu dữ liệu | Ràng buộc | Ý nghĩa |\\r\\n311: |---|---|---|---|\\r\\n312: | `id` | `BIGINT` | PK, tự tăng | Định danh giao dịch. |\\r\\n313: | `booking_code` | `VARCHAR(50)` | NOT NULL, UNIQUE | Mã đặt vé duy nhất từ hệ thống bán vé. |\\r\\n314: | `od_product_id` | `BIGINT` | FK → `od_products.id`, NOT NULL | Sản phẩm OD được mua. |\\r\\n315: | `seat_id` | `BIGINT` | FK → `seats.id`, có thể null | Ghế được gán; có thể chưa có khi mới giữ chỗ. |\\r\\n316: | `status` | `VARCHAR(20)` | NOT NULL | Trạng thái: `held`, `confirmed`, `cancelled`, `refunded`. |\\r\\n317: | `channel` | `VARCHAR(30)` | Có thể null | Kênh bán như web, ứng dụng, quầy hoặc đại lý. |\\r\\n318: | `booked_price` | `NUMERIC(14,2)` | NOT NULL, `\u003e= 0` | Giá đã được chốt cho booking. |\\r\\n319: | `booked_at` | `TIMESTAMPTZ` | NOT NULL | Thời điểm đặt vé. |\\r\\n320: | `cancelled_at` | `TIMESTAMPTZ` | Có thể null | Thời điểm hủy vé. |\\r\\n321: | `refunded_at` | `TIMESTAMPTZ` | Có thể null | Thời điểm hoàn tiền. |\\r\\n322: | `created_at` | `TIMESTAMPTZ` | NOT NULL | Thời điểm tạo bản ghi. |\\r\\n323: | `updated_at` | `TIMESTAMPTZ` | NOT NULL | Thời điểm cập nhật gần nhất. |\\r\\n324: \\r\\n325: **Tác dụng:** phản ánh nhu cầu thực tế và tình trạng sử dụng ghế. Khi có mua hoặc hủy vé, hệ thống có thể tính lại dự báo, quota, bid price và giá.\\r\\n326: \\r\\n327: ## 4. Nhóm kết quả dự báo và tối ưu\\r\\n328: \\r\\n329: ### 4.1. `demand_forecasts` — Kết quả dự báo nhu cầu\\r\\n330: \\r\\n331: Lưu dự báo theo từng sản phẩm OD tại từng thời điểm và số ngày còn lại trước ngày chạy.\\r\\n332: \\r\\n333: | Field | Kiểu dữ liệu | Ràng buộc | Ý nghĩa |\\r\\n334: |---|---|---|---|\\r\\n335: | `id` | `BIGINT` | PK, tự tăng | Định danh kết quả dự báo. |\\r\\n336: | `od_product_id` | `BIGINT` | FK → `od_products.id`, NOT NULL, CASCADE DELETE | Sản phẩm được dự báo. |\\r\\n337: | `forecast_at` | `TIMESTAMPTZ` | NOT NULL | Thời điểm mô hình chạy dự báo. |\\r\\n338: | `lead_days` | `INTEGER` | NOT NULL, `\u003e= 0` | Số ngày từ thời điểm dự báo đến ngày tàu chạy. |\\r\\n339: | `demand_point` | `NUMERIC(12,3)` | NOT NULL, `\u003e= 0` | Giá trị dự báo điểm. |\\r\\n340: | `demand_p10` | `NUMERIC(12,3)` | Có thể null, `\u003e= 0` | Phân vị 10%, đại diện kịch bản nhu cầu thấp. |\\r\\n341: | `demand_p50` | `NUMERIC(12,3)` | Có thể null, `\u003e= 0` | Phân vị 50%, trung vị dự báo. |\\r\\n342: | `demand_p90` | `NUMERIC(12,3)` | Có thể null, `\u003e= 0` | Phân vị 90%, đại diện kịch bản nhu cầu cao. |\\r\\n343: | `model_version` | `VARCHAR(80)` | Có thể null | Phiên bản mô hình tạo ra kết quả. |\\r\\n344: | `created_at` | `TIMESTAMPTZ` | NOT NULL | Thời điểm lưu kết quả. |\\r\\n345: \\r\\n346: Các phân vị phải thỏa `p10 \u003c= p50 \u003c= p90` khi cùng có dữ liệu. Tổ hợp `(od_product_id, forecast_at, lead_days)` là duy nhất.\\r\\n347: \\r\\n348: **Tác dụng:** cấp dữ liệu cho dashboard nhu cầu, bài toán tối ưu hạn ngạch và so sánh nhu cầu dự kiến giữa các OD.\\r\\n349: \\r\\n350: ### 4.2. `bid_prices` — Chi phí cơ hội theo chặng\\r\\n351: \\r\\n352: Lưu bid price của từng loại chỗ trên từng chặng tại mỗi lần chạy tối ưu.\\r\\n353: \\r\\n354: | Field | Kiểu dữ liệu | Ràng buộc | Ý nghĩa |\\r\\n355: |---|---|---|---|\\r\\n356: | `id` | `BIGINT` | PK, tự tăng | Định danh kết quả bid price. |\\r\\n357: | `segment_id` | `BIGINT` | FK → `segments.id`, NOT NULL, CASCADE DELETE | Chặng được định giá cơ hội. |\\r\\n358: | `seat_type` | `VARCHAR(30)` | NOT NULL | Loại chỗ áp dụng. |\\r\\n359: | `bid_price` | `NUMERIC(14,2)` | NOT NULL, `\u003e= 0` | Chi phí cơ hội của một chỗ trên chặng. |\\r\\n360: | `remaining_capacity` | `INTEGER` | NOT NULL, `\u003e= 0` | Sức chứa còn lại khi thuật toán chạy. |\\r\\n361: | `calculated_at` | `TIMESTAMPTZ` | NOT NULL | Thời điểm tính toán. |\\r\\n362: | `run_version` | `VARCHAR(80)` | NOT NULL | Mã phiên chạy để nhóm và phục hồi kết quả. |\\r\\n363: | `is_active` | `BOOLEAN` | NOT NULL | Đánh dấu phiên kết quả đang được sử dụng. |\\r\\n364: | `created_at` | `TIMESTAMPTZ` | NOT NULL | Thời điểm lưu bản ghi. |\\r\\n365: \\r\\n366: Tổ hợp `(segment_id, seat_type, run_version)` là duy nhất.\\r\\n367: \\r\\n368: **Tác dụng:** giúp hệ thống không bán rẻ một OD đi qua chặng khan hiếm. Tổng bid price của các chặng mà OD đi qua tạo thành `opportunity_cost` cho báo giá.\\r\\n369: \\r\\n370: ### 4.3. `quotas` — Hạn ngạch bán\\r\\n371: \\r\\n372: Lưu số lượng chỗ đề xuất được phép bán cho từng sản phẩm OD theo mỗi phiên tối ưu.\\r\\n373: \\r\\n374: | Field | Kiểu dữ liệu | Ràng buộc | Ý nghĩa |\\r\\n375: |---|---|---|---|\\r\\n376: | `id` | `BIGINT` | PK, tự tăng | Định danh hạn ngạch. |\\r\\n377: | `od_product_id` | `BIGINT` | FK → `od_products.id`, NOT NULL, CASCADE DELETE | Sản phẩm OD nhận hạn ngạch. |\\r\\n378: | `quota` | `INTEGER` | NOT NULL, `\u003e= 0` | Số chỗ được phân bổ cho sản phẩm. |\\r\\n379: | `calculated_at` | `TIMESTAMPTZ` | NOT NULL | Thời điểm tính hạn ngạch. |\\r\\n380: | `run_version` | `VARCHAR(80)` | NOT NULL | Mã phiên chạy tối ưu. |\\r\\n381: | `is_active` | `BOOLEAN` | NOT NULL | Đánh dấu phiên hạn ngạch đang áp dụng. |\\r\\n382: | `created_at` | `TIMESTAMPTZ` | NOT NULL | Thời điểm lưu bản ghi. |\\r\\n383: \\r\\n384: Tổ hợp `(od_product_id, run_version)` là duy nhất.\\r\\n385: \\r\\n386: **Tác dụng:** cân bằng chỗ giữa khách đi chặng dài, chặng ngắn và ga trung gian; tránh một nhóm OD chiếm toàn bộ sức chứa.\\r\\n387: \\r\\n388: ## 5. Nhóm chính sách và định giá động\\r\\n389: \\r\\n390: ### 5.1. `price_policies` — Chính sách kiểm soát giá\\r\\n391: \\r\\n392: Lưu trần, sàn và mức biến động giá tối đa đã được cấu hình hoặc phê duyệt. `od_product_id` có thể null để biểu diễn chính sách chung; khi có giá trị, chính sách áp dụng cho sản phẩm cụ thể.\\r\\n393: \\r\\n394: | Field | Kiểu dữ liệu | Ràng buộc | Ý nghĩa |\\r\\n395: |---|---|---|---|\\r\\n396: | `id` | `BIGINT` | PK, tự tăng | Định danh chính sách. |\\r\\n397: | `od_product_id` | `BIGINT` | FK → `od_products.id`, có thể null, CASCADE DELETE | Sản phẩm áp dụng chính sách; null nếu là chính sách chung. |\\r\\n398: | `name` | `VARCHAR(120)` | NOT NULL | Tên chính sách. |\\r\\n399: | `min_price` | `NUMERIC(14,2)` | NOT NULL, `\u003e= 0` | Giá sàn được phép. |\\r\\n400: | `max_price` | `NUMERIC(14,2)` | NOT NULL, `\u003e= min_price` | Giá trần được phép. |\\r\\nThe above content does NOT show the entire file contents. If you need to view any lines of the file which were not shown to complete your task, call this tool again to view those lines.\\n\"}"}
