NTITY PRIMARY KEY,\\r\\n66:     trip_id             BIGINT NOT NULL REFERENCES trips(id) ON DELETE CASCADE,\\r\\n67:     sequence_no         INTEGER NOT NULL,\\r\\n68:     origin_station_id   BIGINT NOT NULL REFERENCES stations(id),\\r\\n69:     destination_station_id BIGINT NOT NULL REFERENCES stations(id),\\r\\n70:     departure_at        TIMESTAMPTZ NOT NULL,\\r\\n71:     arrival_at          TIMESTAMPTZ NOT NULL,\\r\\n72:     distance_km         NUMERIC(8,2) NOT NULL,\\r\\n73:     created_at          TIMESTAMPTZ NOT NULL DEFAULT CURRENT_TIMESTAMP,\\r\\n74:     UNIQUE (trip_id, sequence_no),\\r\\n75:     UNIQUE (trip_id, origin_station_id, destination_station_id),\\r\\n76:     CHECK (sequence_no \u003e 0),\\r\\n77:     CHECK (origin_station_id \u003c\u003e destination_station_id),\\r\\n78:     CHECK (arrival_at \u003e departure_at),\\r\\n79:     CHECK (distance_km \u003e 0)\\r\\n80: );\\r\\n81: \\r\\n82: CREATE TABLE seats (\\r\\n83:     id              BIGINT GENERATED ALWAYS AS IDENTITY PRIMARY KEY,\\r\\n84:     trip_id         BIGINT NOT NULL REFERENCES trips(id) ON DELETE CASCADE,\\r\\n85:     coach_no        VARCHAR(10) NOT NULL,\\r\\n86:     seat_no         VARCHAR(10) NOT NULL,\\r\\n87:     seat_type       VARCHAR(30) NOT NULL REFERENCES seat_types(code),\\r\\n88:     status          VARCHAR(20) NOT NULL DEFAULT 'available',\\r\\n89:     created_at      TIMESTAMPTZ NOT NULL DEFAULT CURRENT_TIMESTAMP,\\r\\n90:     UNIQUE (trip_id, coach_no, seat_no),\\r\\n91:     CHECK (status IN ('available', 'locked', 'maintenance'))\\r\\n92: );\\r\\n93: \\r\\n94: CREATE TABLE segment_capacities (\\r\\n95:     segment_id      BIGINT NOT NULL REFERENCES segments(id) ON DELETE CASCADE,\\r\\n96:     seat_type       VARCHAR(30) NOT NULL REFERENCES seat_types(code),\\r\\n97:     capacity        INTEGER NOT NULL,\\r\\n98:     created_at      TIMESTAMPTZ NOT NULL DEFAULT CURRENT_TIMESTAMP,\\r\\n99:     updated_at      TIMESTAMPTZ NOT NULL DEFAULT CURRENT_TIMESTAMP,\\r\\n100:     PRIMARY KEY (segment_id, seat_type),\\r\\n101:     CHECK (capacity \u003e= 0)\\r\\n102: );\\r\\n103: \\r\\n104: CREATE TABLE segment_inventory (\\r\\n105:     segment_id      BIGINT NOT NULL,\\r\\n106:     seat_type       VARCHAR(30) NOT NULL,\\r\\n107:     remaining       INTEGER NOT NULL,\\r\\n108:     updated_at      TIMESTAMPTZ NOT NULL DEFAULT CURRENT_TIMESTAMP,\\r\\n109:     PRIMARY KEY (segment_id, seat_type),\\r\\n110:     FOREIGN KEY (segment_id, seat_type)\\r\\n111:         REFERENCES segment_capacities(segment_id, seat_type) ON DELETE CASCADE,\\r\\n112:     CHECK (remaining \u003e= 0)\\r\\n113: );\\r\\n114: \\r\\n115: CREATE TABLE od_products (\\r\\n116:     id                  BIGINT GENERATED ALWAYS AS IDENTITY PRIMARY KEY,\\r\\n117:     trip_id             BIGINT NOT NULL REFERENCES trips(id) ON DELETE CASCADE,\\r\\n118:     origin_station_id   BIGINT NOT NULL REFERENCES stations(id),\\r\\n119:     destination_station_id BIGINT NOT NULL REFERENCES stations(id),\\r\\n120:     seat_type           VARCHAR(30) NOT NULL REFERENCES seat_types(code),\\r\\n121:     fare_class          VARCHAR(30) NOT NULL DEFAULT 'standard' REFERENCES fare_classes(code),\\r\\n122:     base_price          NUMERIC(14,2) NOT NULL,\\r\\n123:     distance_km         NUMERIC(8,2) NOT NULL,\\r\\n124:     is_active           BOOLEAN NOT NULL DEFAULT TRUE,\\r\\n125:     created_at          TIMESTAMPTZ NOT NULL DEFAULT CURRENT_TIMESTAMP,\\r\\n126:     updated_at          TIMESTAMPTZ NOT NULL DEFAULT CURRENT_TIMESTAMP,\\r\\n127:     UNIQUE (trip_id, origin_station_id, destination_station_id, seat_type, fare_class),\\r\\n128:     CHECK (origin_station_id \u003c\u003e destination_station_id),\\r\\n129:     CHECK (base_price \u003e= 0),\\r\\n130:     CHECK (distance_km \u003e 0)\\r\\n131: );\\r\\n132: \\r\\n133: CREATE TABLE od_product_segments (\\r\\n134:     od_product_id   BIGINT NOT NULL REFERENCES od_products(id) ON DELETE CASCADE,\\r\\n135:     segment_id      BIGINT NOT NULL REFERENCES segments(id) ON DELETE CASCADE,\\r\\n136:     PRIMARY KEY (od_product_id, segment_id)\\r\\n137: );\\r\\n138: \\r\\n139: CREATE TABLE bookings (\\r\\n140:     id              BIGINT GENERATED ALWAYS AS IDENTITY PRIMARY KEY,\\r\\n141:     booking_code    VARCHAR(50) NOT NULL UNIQUE,\\r\\n142:     od_product_id   BIGINT NOT NULL REFERENCES od_products(id),\\r\\n143:     seat_id         BIGINT REFERENCES seats(id),\\r\\n144:     status          VARCHAR(20) NOT NULL DEFAULT 'confirmed',\\r\\n145:     channel         VARCHAR(30),\\r\\n146:     booked_price    NUMERIC(14,2) NOT NULL,\\r\\n147:     booked_at       TIMESTAMPTZ NOT NULL,\\r\\n148:     expires_at      TIMESTAMPTZ,\\r\\n149:     cancelled_at    TIMESTAMPTZ,\\r\\n150:     refunded_at     TIMESTAMPTZ,\\r\\n151:     created_at      TIMESTAMPTZ NOT NULL DEFAULT CURRENT_TIMESTAMP,\\r\\n152:     updated_at      TIMESTAMPTZ NOT NULL DEFAULT CURRENT_TIMESTAMP,\\r\\n153:     CHECK (status IN ('held', 'confirmed', 'cancelled', 'refunded')),\\r\\n154:     CHECK (booked_price \u003e= 0),\\r\\n155:     CHECK (expires_at IS NULL OR expires_at \u003e booked_at),\\r\\n156:     CHECK (cancelled_at IS NULL OR cancelled_at \u003e= booked_at),\\r\\n157:     CHECK (refunded_at IS NULL OR refunded_at \u003e= booked_at)\\r\\n158: );\\r\\n159: \\r\\n160: CREATE TABLE search_logs (\\r\\n161:     id                  BIGINT GENERATED ALWAYS AS IDENTITY PRIMARY KEY,\\r\\n162:     searched_at         TIMESTAMPTZ NOT NULL,\\r\\n163:     origin_station_id   BIGINT NOT NULL REFERENCES stations(id),\\r\\n164:     destination_station_id BIGINT NOT NULL REFERENCES stations(id),\\r\\n165:     seat_type           VARCHAR(30) NOT NULL REFERENCES seat_types(code),\\r\\n166:     service_date        DATE NOT NULL,\\r\\n167:     result              VARCHAR(20) NOT NULL,\\r\\n168:     od_product_id       BIGINT REFERENCES od_products(id) ON DELETE SET NULL,\\r\\n169:     channel             VARCHAR(30),\\r\\n170:     created_at          TIMESTAMPTZ NOT NULL DEFAULT CURRENT_TIMESTAMP,\\r\\n171:     CHECK (origin_station_id \u003c\u003e destination_station_id),\\r\\n172:     CHECK (result IN ('found', 'sold_out', 'no_result'))\\r\\n173: );\\r\\n174: \\r\\n175: CREATE TABLE gap_combinations (\\r\\n176:     id                      BIGINT GENERATED ALWAYS AS IDENTITY PRIMARY KEY,\\r\\n177:     seat_id                 BIGINT NOT NULL REFERENCES seats(id) ON DELETE CASCADE,\\r\\n178:     from_station_id         BIGINT NOT NULL REFERENCES stations(id),\\r\\n179:     to_station_id           BIGINT NOT NULL REFERENCES stations(id),\\r\\n180:     suggested_od_product_id BIGINT REFERENCES od_products(id) ON DELETE SET NULL,\\r\\n181:     run_version             VARCHAR(80) NOT NULL,\\r\\n182:     is_active               BOOLEAN NOT NULL DEFAULT TRUE,\\r\\n183:     created_at              TIMESTAMPTZ NOT NULL DEFAULT CURRENT_TIMESTAMP,\\r\\n184:     UNIQUE (seat_id, from_station_id, to_station_id, run_version),\\r\\n185:     CHECK (from_station_id \u003c\u003e to_station_id)\\r\\n186: );\\r\\n187: \\r\\n188: CREATE TABLE demand_forecasts (\\r\\n189:     id                  BIGINT GENERATED ALWAYS AS IDENTITY PRIMARY KEY,\\r\\n190:     od_product_id       BIGINT NOT NULL REFERENCES od_products(id) ON DELETE CASCADE,\\r\\n191:     forecast_at         TIMESTAMPTZ NOT NULL,\\r\\n192:     lead_days           INTEGER NOT NULL,\\r\\n193:     demand_point        NUMERIC(12,3) NOT NULL,\\r\\n194:     demand_p10          NUMERIC(12,3),\\r\\n195:     demand_p50          NUMERIC(12,3),\\r\\n196:     demand_p90          NUMERIC(12,3),\\r\\n197:     model_version       VARCHAR(80),\\r\\n198:     created_at          TIMESTAMPTZ NOT NULL DEFAULT CURRENT_TIMESTAMP,\\r\\n199:     UNIQUE (od_product_id, forecast_at, lead_days),\\r\\n200:     CHECK (lead_days \u003e= 0),\\r\\n201:     CHECK (demand_point \u003e= 0),\\r\\n202:     CHECK (demand_p10 IS NULL OR demand_p10 \u003e= 0),\\r\\n203:     CHECK (demand_p50 IS NULL OR demand_p50 \u003e= 0),\\r\\n204:     CHECK (demand_p90 IS NULL OR demand_p90 \u003e= 0),\\r\\n205:     CHECK (demand_p10 IS NULL OR demand_p50 IS NULL OR demand_p10 \u003c= demand_p50),\\r\\n206:     CHECK (demand_p50 IS NULL OR demand_p90 IS NULL OR demand_p50 \u003c= demand_p90)\\r\\n207: );\\r\\n208: \\r\\n209: CREATE TABLE bid_prices (\\r\\n210:     id              BIGINT GENERATED ALWAYS AS IDENTITY PRIMARY KEY,\\r\\n211:     segment_id      BIGINT NOT NULL REFERENCES segments(id) ON DELETE CASCADE,\\r\\n212:     seat_type       VARCHAR(30) NOT NULL REFERENCES seat_types(code),\\r\\n213:     bid_price       NUMERIC(14,2) NOT NULL,\\r\\n214:     remaining_capacity INTEGER NOT NULL,\\r\\n215:     calculated_at   TIMESTAMPTZ NOT NULL,\\r\\n216:     run_version     VARCHAR(80) NOT NULL,\\r\\n217:     is_active       BOOLEAN NOT NULL DEFAULT TRUE,\\r\\n218:     created_at      TIMESTAMPTZ NOT NULL DEFAULT CURRENT_TIMESTAMP,\\r\\n219:     UNIQUE (segment_id, seat_type, run_version),\\r\\n220:     CHECK (bid_price \u003e= 0),\\r\\n221:     CHECK (remaining_capacity \u003e= 0)\\r\\n222: );\\r\\n223: \\r\\n224: CREATE TABLE quotas (\\r\\n225:     id              BIGINT GENERATED ALWAYS AS IDENTITY PRIMARY KEY,\\r\\n226:     od_product_id   BIGINT NOT NULL REFERENCES od_products(id) ON DELETE CASCADE,\\r\\n227:     quota           INTEGER NOT NULL,\\r\\n228:     calculated_at   TIMESTAMPTZ NOT NULL,\\r\\n229:     run_version     VARCHAR(80) NOT NULL,\\r\\n230:     is_active       BOOLEAN NOT NULL DEFAULT TRUE,\\r\\n231:     created_at      TIMESTAMPTZ NOT NULL DEFAULT CURRENT_TIMESTAMP,\\r\\n232:     UNIQUE (od_product_id, run_version),\\r\\n233:     CHECK (quota \u003e= 0)\\r\\n234: );\\r\\n235: \\r\\n236: CREATE TABLE price_policies (\\r\\n237:     id                  BIGINT GENERATED ALWAYS AS IDENTITY PRIMARY KEY,\\r\\n238:     od_product_id       BIGINT REFERENCES od_products(id) ON DELETE CASCADE,\\r\\n239:     name                VARCHAR(120) NOT NULL,\\r\\n240:     min_price           NUMERIC(14,2) NOT NULL,\\r\\n241:     max_price           NUMERIC(14,2) NOT NULL,\\r\\n242:     max_step_change     NUMERIC(14,2) NOT NULL,\\r\\n243:     valid_from          TIMESTAMPTZ NOT NULL,\\r\\n244:     valid_to            TIMESTAMPTZ,\\r\\n245:     status              VARCHAR(20) NOT NULL DEFAULT 'draft',\\r\\n246:     created_by          VARCHAR(120),\\r\\n247:     approved_by         VARCHAR(120),\\r\\n248:     created_at          TIMESTAMPTZ NOT NULL DEFAULT CURRENT_TIMESTAMP,\\r\\n249:     updated_at          TIMESTAMPTZ NOT NULL DEFAULT CURRENT_TIMESTAMP,\\r\\n250:     CHECK (min_price \u003e= 0),\\r\\n251:     CHECK (max_price \u003e= min_price),\\r\\n252:     CHECK (max_step_change \u003e= 0),\\r\\n253:     CHECK (valid_to IS NULL OR valid_to \u003e valid_from),\\r\\n254:     CHECK (status IN ('draft', 'active', 'inactive'))\\r\\n255: );\\r\\n256: \\r\\n257: CREATE TABLE price_quotes (\\r\\n258:     id                  BIGINT GENERATED ALWAYS AS IDENTITY PRIMARY KEY,\\r\\n259:     od_product_id       BIGINT NOT NULL REFERENCES od_products(id),\\r\\n260:     policy_id           BIGINT REFERENCES price_policies(id),\\r\\n261:     opportunity_cost    NUMERIC(14,2) NOT NULL,\\r\\n262:     proposed_price      NUMERIC(14,2) NOT NULL,\\r\\n263:     final_price         NUMERIC(14,2) NOT NULL,\\r\\n264:     decision            VARCHAR(20) NOT NULL,\\r\\n265:     explanation         JSONB NOT NULL DEFAULT '{}'::JSONB,\\r\\n266:     run_version         VARCHAR(80),\\r\\n267:     quoted_at           TIMESTAMPTZ NOT NULL DEFAULT CURRENT_TIMESTAMP,\\r\\n268:     expires_at          TIMESTAMPTZ,\\r\\n269:     confirmed_at        TIMESTAMPTZ,\\r\\n270:     created_at          TIMESTAMPTZ NOT NULL DEFAULT CURRENT_TIMESTAMP,\\r\\n271:     CHECK (opportunity_cost \u003e= 0),\\r\\n272:     CHECK (proposed_price \u003e= 0),\\r\\n273:     CHECK (final_price \u003e= 0),\\r\\n274:     CHECK (decision IN ('accepted', 'rejected', 'blocked')),\\r\\n275:     CHECK (expires_at IS NULL OR expires_at \u003e quoted_at),\\r\\n276:     CHECK (confirmed_at IS NULL OR confirmed_at \u003e= quoted_at)\\r\\n277: );\\r\\n278: \\r\\n279: CREATE TABLE audit_logs (\\r\\n280:     id              BIGINT GENERATED ALWAYS AS IDENTITY PRIMARY KEY,\\r\\n281:     actor           VARCHAR(120) NOT NULL,\\r\\n282:     action          VARCHAR(60) NOT NULL,\\r\\n283:     entity_type     VARCHAR(60) NOT NULL,\\r\\n284:     entity_id       VARCHAR(80),\\r\\n285:     before_data     JSONB,\\r\\n286:     after_data      JSONB,\\r\\n287:     created_at      TIMESTAMPTZ NOT NULL DEFAULT CURRENT_TIMESTAMP\\r\\n288: );\\r\\n289: \\r\\n290: CREATE UNIQUE INDEX ux_bid_prices_active\\r\\n291:     ON bid_prices (segment_id, seat_type)\\r\\n292:     WHERE is_active = TRUE;\\r\\n293: \\r\\n294: CREATE UNIQUE INDEX ux_quotas_active\\r\\n295:     ON quotas (od_product_id)\\r\\n296:     WHERE is_active = TRUE;\\r\\n297: \\r\\n298: CREATE INDEX ix_search_logs_demand\\r\\n299:     ON search_logs (service_date, origin_station_id, destination_station_id, seat_type, searched_at);\\r\\n300: \\r\\n301: CREATE INDEX ix_od_product_segments_segment\\r\\n302:     ON od_product_segments (segment_id, od_product_id);\\r\\n303: \\r\\n304: CREATE INDEX ix_gap_combinations_lookup\\r\\n305:     ON gap_combinations (from_station_id, to_station_id, is_active);\\r\\n306: \\nThe above content shows the entire, complete file contents of the requested file.\\n\"}"}
